import { haptics } from '@/lib/haptics';
import { activityTracker } from '@/lib/activityTracker';
import { usePlan } from '@/hooks/usePlan';
import { UpgradeWall } from '@/components/plan/UpgradeWall';

type InterviewPhase = 'setup' | 'preview' | 'active' | 'summary';
type Json = string | number | boolean | null | { [key: string]: Json | undefined } | Json[];

function InterviewPageContent() {
  useEffect(() => {
    activityTracker.setActiveFeature('Mock Interview');
    return () => { activityTracker.setActiveFeature(null); };
  }, []);
  const navigate = useNavigate();
  const { user, loading, authReady, authSettled } = useAuth();
  const { currentResume, currentResumeId, setCurrentResume, setCurrentResumeId } = useResumeStore();
  const hydrated = useResumeStoreHydration();
  const { isPro, isLoading: planLoading } = usePlan();
  const { data: resumes, isLoading: resumesLoading, isFetched: resumesFetched } = useResumes();
  const { createResume } = useResumeMutations();
  const scrollRef = useRef<HTMLDivElement>(null);
  const [textInput, setTextInput] = useState('');
  const [showTextInput, setShowTextInput] = useState(true);
  const [pendingJobDescription, setPendingJobDescription] = useState<string | undefined>();
  const [showHistory, setShowHistory] = useState(false);
  const [showTips, setShowTips] = useState(false);
  const [showEndConfirm, setShowEndConfirm] = useState(false);
  const [sessionSaved, setSessionSaved] = useState(false);
  const [showAnswerLibrary, setShowAnswerLibrary] = useState(false);
  const [savedSessionId, setSavedSessionId] = useState<string | undefined>();
  const [creatingSampleResume, setCreatingSampleResume] = useState(false);
  const [showResumeDraft, setShowResumeDraft] = useState(false);
  const [draftDismissed, setDraftDismissed] = useState(false);
  const activeJobDescriptionRef = useRef<string | undefined>();
  const activeInterviewTypeRef = useRef<string>('general');
  const draftIdRef = useRef<string | null>(null);
  const saveSession = useSaveInterviewSession();
  const upsertDraft = useUpsertInterviewDraft();
  const deleteDraft = useDeleteInterviewDraft();
  const { data: latestDraft } = useLatestInterviewDraft();

  // Resume guard - require a resume for interview practice (only after hydration)
  // Any non-null resume object is valid — fullName is optional
  const hasValidResume = currentResume != null;

  const {
    status,
    transcript,
    isStarted,
    summary,
    error,
    interimText,
    speechSupported,
    speechRecognitionAvailable,
    elapsedSeconds,
    voiceGender,
    setVoiceGender,
    scores,
    latestScore,
    dismissScore,
    sttEngine,
    roleAnalysis,
    isAnalyzingRole,
    analyzeRole,
    startInterview,
    startListening,
    stopListening,
    sendTextMessage,
    endInterview,
    resetInterview,
    retryAI,
    skipAITurn,
    retryCurrentQuestion,
    submitAnswerNow,
    resumeFromDraft,
  } = useVoiceInterview(currentResume);

  // Auto-select Master CV (or most recent resume) if the store is empty.
  // Without this, /interview lands on the empty state even when the user
  // already has resumes — the persisted store can be wiped after sign-out
  // or when arriving from a deep link.
  useEffect(() => {
    if (!hydrated) return;
    if (currentResume) return;
    if (!resumes || resumes.length === 0) return;
    const sorted = [...resumes].sort((a, b) => {
      if (a.is_primary && !b.is_primary) return -1;
      if (!a.is_primary && b.is_primary) return 1;
      const aT = a.updated_at ? new Date(a.updated_at).getTime() : 0;
      const bT = b.updated_at ? new Date(b.updated_at).getTime() : 0;
      return bT - aT;
    });
    const pick = sorted[0];
    if (!pick) return;
    setCurrentResumeId(pick.id);
    setCurrentResume(dbToResumeData(pick));
  }, [hydrated, currentResume, resumes, setCurrentResume, setCurrentResumeId]);

  // Surface the resume-previous-session prompt when a fresh draft exists
  // (less than 24h old, not yet promoted to a completed session).
  useEffect(() => {
    if (draftDismissed) return;
    if (isStarted) return;
    if (!latestDraft) return;
    setShowResumeDraft(true);
  }, [latestDraft, isStarted, draftDismissed]);

  // No navigation redirect — show an in-page empty state instead

  // Derive phase
  const phase: InterviewPhase = summary
    ? 'summary'
    : isStarted
      ? 'active'
      : pendingJobDescription !== undefined
        ? 'preview'
        : 'setup';

  // Auto-scroll transcript
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [transcript, status]);

  // Show errors as toast with specific messages and auto-show text input
  useEffect(() => {
    if (error) {
      let title = 'Error';
      let description = error;
      if (error.toLowerCase().includes('microphone') && error.toLowerCase().includes('denied')) {
        title = 'Microphone Blocked';
        description = 'Please allow microphone access in your browser settings, or use the Type button.';
        setShowTextInput(true);
      } else if (error.toLowerCase().includes('not supported') || error.toLowerCase().includes('not available')) {
        title = 'Speech Recognition Unavailable';
        setShowTextInput(true);
      } else if (error.toLowerCase().includes('timed out') || error.toLowerCase().includes('connection error')) {
        title = 'Connection Issue';
        description = error + ' You can use the Type button instead.';
        setShowTextInput(true);
      } else if (error.toLowerCase().includes('voice input unavailable')) {
        title = 'Voice Unavailable';
        setShowTextInput(true);
      }
      toast.error(title, { description });
    }
  }, [error]);

  const handleSetupStart = useCallback((jobDescription?: string, options?: { quickPractice?: boolean }) => {
    if (options?.quickPractice) {
      // Quick practice — skip preview, start directly with quickPractice flag
      activeInterviewTypeRef.current = 'quick-practice';
      activeJobDescriptionRef.current = undefined;
      startInterview(undefined, true);
    } else if (jobDescription) {
      // Go to preview phase for job-targeted interviews
      activeInterviewTypeRef.current = 'job-targeted';
      activeJobDescriptionRef.current = jobDescription;
      setPendingJobDescription(jobDescription);
      analyzeRole(jobDescription);
    } else {
      // General interview — skip preview, start directly
      activeInterviewTypeRef.current = 'general';
      activeJobDescriptionRef.current = undefined;
      startInterview();
    }
  }, [analyzeRole, startInterview]);

  const handlePreviewReady = useCallback(() => {
    startInterview(pendingJobDescription);
    setPendingJobDescription(undefined);
  }, [startInterview, pendingJobDescription]);

  const handleToggle = () => {
    if (status === 'listening') {
      stopListening();
    } else if (status === 'idle' || status === 'ready') {
      startListening();
    } else if (status === 'speaking') {
      // Allow interrupting AI
      window.speechSynthesis?.cancel();
      startListening();
    }
  };

  const handleSendText = () => {
    if (!textInput.trim()) return;
    sendTextMessage(textInput.trim());
    setTextInput('');
  };

  const handleReset = useCallback(() => {
    resetInterview();
    setPendingJobDescription(undefined);
    draftIdRef.current = null;
  }, [resetInterview]);

  // Per-turn draft persistence: every time the transcript grows (or duration
  // ticks past noticeable boundaries), upsert the in-progress session so we
  // can offer "Resume previous interview?" within the next 24h.
  useEffect(() => {
    if (!isStarted) return;
    if (!user) return;
    if (transcript.length === 0) return;
    const messages = transcript.map((t) => ({
      id: t.id,
      role: t.role,
      text: t.text,
      timestamp: t.timestamp instanceof Date ? t.timestamp.toISOString() : String(t.timestamp),
    }));
    upsertDraft.mutate(
      {
        draft_id: draftIdRef.current ?? undefined,
        resume_id: currentResumeId ?? undefined,
        interview_type: activeInterviewTypeRef.current,
        job_description: activeJobDescriptionRef.current ?? null,
        messages: messages as unknown as Json,
        duration_seconds: elapsedSeconds,
      },
      {
        onSuccess: (row) => {
          if (row?.id) draftIdRef.current = row.id;
        },
      }
    );
    // Only re-run when the count of transcript entries changes — we don't
    // need to re-save on every interim text tick.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isStarted, user, transcript.length]);

  // Resume a prior in-progress interview (within 24h). Restores resume,
  // transcript, AI context, mode (job-targeted / quick / general), JD, and
  // the elapsed timer — without spending AI credits regenerating the
  // last question that's already on screen.
  const handleResumeDraft = useCallback(() => {
    if (!latestDraft) return;
    setShowResumeDraft(false);
    setDraftDismissed(true);
    draftIdRef.current = latestDraft.id;
    activeInterviewTypeRef.current = latestDraft.interview_type || 'general';
    activeJobDescriptionRef.current = latestDraft.job_description || undefined;
    setPendingJobDescription(undefined);

    // Restore the resume the original session was practicing against, so
    // the AI has matching context and the picker shows the right entry.
    if (latestDraft.resume_id && resumes) {
      const restored = resumes.find((r) => r.id === latestDraft.resume_id);
      if (restored) {
        setCurrentResumeId(restored.id);
        setCurrentResume(dbToResumeData(restored));
      }
    }

    // Parse stored messages (Json column) into transcript entries.
    const rawMessages = Array.isArray(latestDraft.messages) ? latestDraft.messages : [];
    const messages = (rawMessages as Array<{ id?: string; role?: string; text?: string; timestamp?: string }>)
      .filter((m) => m && (m.role === 'user' || m.role === 'interviewer') && typeof m.text === 'string')
      .map((m) => ({
        id: m.id,
        role: m.role as 'user' | 'interviewer',
        text: m.text as string,
        timestamp: m.timestamp,
      }));

    resumeFromDraft({
      messages,
      jobDescription: latestDraft.job_description,
      interviewType: latestDraft.interview_type,
      durationSeconds: latestDraft.duration_seconds,
    });

    toast.info('Picking up where you left off', {
      description: 'Your previous answers are restored. Tap the mic to continue.',
    });
  }, [latestDraft, resumes, resumeFromDraft, setCurrentResume, setCurrentResumeId]);

  const handleDiscardDraft = useCallback(() => {
    setShowResumeDraft(false);
    setDraftDismissed(true);
    if (latestDraft?.id) {
      deleteDraft.mutate(latestDraft.id);
    }
    draftIdRef.current = null;
  }, [latestDraft, deleteDraft]);

  const handleCreateSampleResume = useCallback(async () => {
    if (!user) {
      toast.error('Please sign in to create a sample resume');
      return;
    }
    setCreatingSampleResume(true);
    try {
      const displayName = user.name?.trim() || (user.email ? user.email.split('@')[0] : null);
      const { resume, title } = buildSampleResume(displayName);
      await createResume.mutateAsync({ resume, title });
      toast.success('Sample resume ready — start your interview now.');
    } catch (err) {
      console.error('[InterviewPage] sample resume creation failed', err);
      toast.error('Could not create sample resume');
    } finally {
      setCreatingSampleResume(false);
    }
  }, [user, createResume]);

  const mins = Math.floor(elapsedSeconds / 60);
  const secs = elapsedSeconds % 60;

  // Single source of truth: parse the AI summary (JSON or legacy markdown) once.
  // Both the auto-save useEffect and the InterviewSummary display consume this.
  const parsedSummary = useMemo(() => {
    if (!summary) return { displayText: '', overallScore: undefined as number | undefined, strengths: [] as string[], improvements: [] as string[] };
    try {
      const cleanJson = summary.replace(/```json\n?|\n?```/g, '').trim();
      if (cleanJson.startsWith('{')) {
        const parsed = JSON.parse(cleanJson);
        const strengths: string[] = parsed.strengths || [];
        const improvements: string[] = parsed.improvements || [];
        const displayText = `**Overall Assessment:**\n${parsed.overallAssessment}\n\n**Strengths:**\n${strengths.map((s: string) => `- ${s}`).join('\n')}\n\n**Areas to Improve:**\n${improvements.map((s: string) => `- ${s}`).join('\n')}\n\n**Score: ${parsed.score}/10**\n\n**Next Steps:**\n${(parsed.nextSteps || []).map((s: string) => `- ${s}`).join('\n')}`;
        return { displayText, overallScore: parsed.score as number | undefined, strengths, improvements };
      }
    } catch (_e) {
      // Fall through to legacy parsing
    }
    // Legacy markdown fallback
    const scoreMatch = summary.match(/Score:\s*(\d+)\/10/i);
    const strengthsMatch = summary.match(/\*\*Strengths:\*\*\n([\s\S]*?)(?=\n\*\*)/);
    const improvementsMatch = summary.match(/\*\*Areas to Improve:\*\*\n([\s\S]*?)(?=\n\*\*)/);
    return {
      displayText: summary,
      overallScore: scoreMatch ? parseInt(scoreMatch[1]) : undefined,
      strengths: strengthsMatch ? strengthsMatch[1].split('\n').filter(l => l.trim().startsWith('-')).map(l => l.replace(/^-\s*/, '').trim()) : [],
      improvements: improvementsMatch ? improvementsMatch[1].split('\n').filter(l => l.trim().startsWith('-')).map(l => l.replace(/^-\s*/, '').trim()) : [],
    };
  }, [summary]);

  const hasUnsavedSession = useRef(false);

  // beforeunload guard — warn if session summary exists but hasn't been saved yet
  useEffect(() => {
    const handleBeforeUnload = (e: BeforeUnloadEvent) => {
      if (hasUnsavedSession.current) {
        e.preventDefault();
        e.returnValue = 'Leave page? Your session results haven\'t been saved yet.';
        return e.returnValue;
      }
    };
    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, []);

  // Auto-save session when summary is shown
  useEffect(() => {
    if (summary && !sessionSaved && user) {
      hasUnsavedSession.current = true;
      setSessionSaved(true);
      saveSession.mutate({
        draft_id: draftIdRef.current ?? undefined,
        resume_id: currentResumeId ?? undefined,
        interview_type: activeInterviewTypeRef.current,
        job_description: activeJobDescriptionRef.current,
        messages: transcript as any,
        overall_score: parsedSummary.overallScore,
        strengths: parsedSummary.strengths,
        improvements: parsedSummary.improvements,
        duration_seconds: elapsedSeconds,
      }, {
        onSuccess: (data) => {
          hasUnsavedSession.current = false;
          draftIdRef.current = null;
          if (data?.id) setSavedSessionId(data.id);
        },
        onError: (err) => {
          hasUnsavedSession.current = true;
          toast.error('Failed to save interview', {
            description: 'A network or authentication error occurred. Your session won\'t be saved in history.',
            action: {
              label: 'Retry',
              onClick: () => setSessionSaved(false), // Resetting allows it to retry saving next render
            }
          });
        }
      });
    }
  }, [summary, sessionSaved, user, transcript, elapsedSeconds, saveSession, parsedSummary]);


  const backTriggeredRef = useRef(false);

  // Show loading while auth, store, or plan data hydrates
  if (loading || !authSettled || !hydrated || planLoading) {
    return <InterviewSkeleton />;
  }

  // Feature gate: Interview Coaching is Pro+
  if (!isPro) {
    return (
      <div className="flex-1 flex items-center justify-center">
        <UpgradeWall
          requiredPlan="pro"
          featureName="Interview Coaching"
          description="Practice real voice interviews with AI that listens, responds, and scores you live."
          features={[
            'Live voice interview practice with AI',
            'Real-time scoring & performance breakdown',
            'Industry-specific question banks',
            'Resume-aware coaching & targeted feedback',
          ]}
        />
      </div>
    );
  }

  // While the resume list is still loading, hold off on a verdict — we
  // don't want to flash the empty state for users who actually have
  // resumes (the auto-select effect will populate `currentResume`).
  if (!hasValidResume && (resumesLoading || !resumesFetched)) {
    return <InterviewSkeleton />;
  }

  // Empty state — only when the user genuinely has zero resumes.
  if (!hasValidResume) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center px-6 py-16 gap-4 text-center">
        <div className="w-16 h-16 rounded-2xl bg-muted flex items-center justify-center">
          <Sparkles className="w-8 h-8 text-muted-foreground opacity-50" />
        </div>
        <div>
          <h2 className="font-semibold text-lg mb-1 text-foreground">No Resume Yet</h2>
          <p className="text-sm text-muted-foreground max-w-sm">
            Wise AI tailors interview questions to your background. Create a resume — or load a sample one — to get started in seconds.
          </p>
        </div>
        <div className="flex flex-col sm:flex-row gap-3 w-full max-w-sm">
          <Button
            variant="outline"
            onClick={handleCreateSampleResume}
            disabled={creatingSampleResume}
            className="min-h-[48px] px-5 flex-1"
          >
            {creatingSampleResume ? 'Creating…' : 'Use Sample Resume'}
          </Button>
          <Button
            onClick={() => navigate('/dashboard?action=create')}
            className="min-h-[48px] px-5 flex-1"
          >
            Create Resume
          </Button>
        </div>
      </div>
    );
  }

  if (phase === 'summary') {
    return (
      <div className="flex-1 flex flex-col overflow-hidden">
        <header className="lg:hidden shrink-0 sticky top-0 z-50 bg-background/95 backdrop-blur-sm border-b border-border px-4 py-3">
          <div className="flex items-center gap-3">
            <BackButton onBeforeBack={() => { handleReset(); return true; }} />
            <Sparkles className="w-5 h-5 text-primary" />
            <h1 className="text-page-title flex-1">Interview Results</h1>
          </div>
        </header>
        <div className="flex-1 overflow-y-auto">
          <InterviewSummary
            summary={parsedSummary.displayText}
            duration={elapsedSeconds}
            scores={scores}
            onRestart={() => { setSessionSaved(false); handleReset(); }}
            onGoHome={() => navigate('/ai-studio')}
            onShowTips={() => setShowTips(true)}
            transcript={transcript}
            candidateName={currentResume?.contactInfo?.fullName || user?.email}
            sessionId={savedSessionId}
            interviewType={activeInterviewTypeRef.current}
            roleContext={activeJobDescriptionRef.current ? 'Job-targeted' : undefined}
          />
          <InterviewTipsSheet open={showTips} onOpenChange={setShowTips} />
        </div>
      </div>
    );
  }

  // Preview screen (job-targeted only)
  if (phase === 'preview') {
    return (
      <div className="flex-1 flex flex-col overflow-hidden">
        <header className="lg:hidden shrink-0 sticky top-0 z-50 bg-background/95 backdrop-blur-sm border-b border-border px-4 py-3">
          <div className="flex items-center gap-3">
            <BackButton
              onBeforeBack={() => {
                setPendingJobDescription(undefined);
                return true;
              }}
              className="text-foreground"
            />
            <Sparkles className="w-5 h-5 text-primary" />
            <h1 className="text-page-title">Interview Preview</h1>
          </div>
        </header>
        <div className="flex-1 overflow-y-auto">
          <div className="px-4 pt-3">
            <ResumePicker
              onChange={() => {
                // Switching resume invalidates the role analysis we generated
                // for the previous resume + JD pair. Drop back to setup so the
                // user can re-confirm the JD against the new resume.
                setPendingJobDescription(undefined);
                toast.info('Resume switched', {
                  description: 'Re-enter the job description to refresh the preview.',
                });
              }}
            />
          </div>
          <InterviewPreview
            roleAnalysis={roleAnalysis}
            isLoading={isAnalyzingRole}
            onReady={handlePreviewReady}
          />
        </div>
      </div>
    );
  }

  // Setup screen
  if (phase === 'setup') {
    return (
      <div className="flex-1 flex flex-col overflow-hidden h-full">
        <header className="lg:hidden shrink-0 sticky top-0 z-50 bg-background/95 backdrop-blur-sm border-b border-border px-4 py-3">
          <div className="flex items-center gap-3">
            <BackButton />
            <Sparkles className="w-5 h-5 text-primary" />
            <h1 className="text-page-title flex-1">Wise AI Interview</h1>
            <button onClick={() => setShowAnswerLibrary(true)} className="touch-manipulation p-2 rounded-full hover:bg-muted active:scale-95 min-w-[44px] min-h-[44px] flex items-center justify-center">
              <BookOpen className="w-5 h-5 text-muted-foreground" />
            </button>
            <button onClick={() => setShowTips(true)} className="touch-manipulation p-2 rounded-full hover:bg-muted active:scale-95 min-w-[44px] min-h-[44px] flex items-center justify-center">
              <Lightbulb className="w-5 h-5 text-muted-foreground" />
            </button>
            <button onClick={() => setShowHistory(true)} className="touch-manipulation p-2 rounded-full hover:bg-muted active:scale-95 min-w-[44px] min-h-[44px] flex items-center justify-center">
              <History className="w-5 h-5 text-muted-foreground" />
            </button>
          </div>
        </header>
        <div className="flex-1 overflow-y-auto">
          <div className="px-4 pt-3">
            <ResumePicker />
          </div>
          <InterviewStatsCard onViewHistory={() => setShowHistory(true)} />
          <div className="mx-4 mt-3 mb-1 flex items-start gap-2 px-3 py-2.5 rounded-xl border border-amber-500/20 bg-amber-500/8">
            <AlertTriangle className="w-4 h-4 text-amber-500 mt-0.5 shrink-0" />
            <div>
              <p className="text-xs font-medium text-foreground">Text-only · AI responses temporarily unavailable</p>
              <p className="text-xs text-muted-foreground mt-0.5">Voice input is not available right now. You can still practise by typing your answers — questions will appear on screen as usual.</p>
            </div>
          </div>
          <InterviewSetup
            hasResume={!!currentResume}
            speechSupported={speechSupported}
            speechRecognitionAvailable={speechRecognitionAvailable}
            voiceGender={voiceGender}
            onVoiceGenderChange={setVoiceGender}
            onStart={handleSetupStart}
            resumeData={currentResume ? { 
              summary: currentResume.summary ?? undefined, 
              experience: currentResume.experience, 
              skills: currentResume.skills 
            } : undefined}
          />
        </div>
        <InterviewHistorySheet open={showHistory} onOpenChange={setShowHistory} />
        <InterviewTipsSheet open={showTips} onOpenChange={setShowTips} />
        <AnswerLibrarySheet open={showAnswerLibrary} onOpenChange={setShowAnswerLibrary} />

        {/* Resume previous in-progress interview prompt (within 24h). */}
        <Sheet open={showResumeDraft} onOpenChange={(open) => { if (!open) setDraftDismissed(true); setShowResumeDraft(open); }}>
          <SheetContent side="bottom" hideCloseButton className="px-6 pb-8">
            <SheetTitle className="text-lg font-bold text-foreground text-center">
              Resume previous interview?
            </SheetTitle>
            <SheetDescription className="text-sm text-muted-foreground text-center mt-1">
              We found an unfinished session
              {latestDraft?.job_title ? ` for ${latestDraft.job_title}` : ''}{' '}
              from earlier today. Pick it up where you left off, or start fresh.
            </SheetDescription>
            <div className="flex flex-col gap-3 mt-6">
              <Button
                className="w-full py-3 rounded-xl font-semibold min-h-[48px]"
                onClick={handleResumeDraft}
              >
                Resume Previous
              </Button>
              <Button
                variant="ghost"
                className="w-full py-3 rounded-xl font-medium bg-muted/50 min-h-[48px]"
                onClick={handleDiscardDraft}
              >
                Discard &amp; Start Fresh
              </Button>
            </div>
          </SheetContent>
        </Sheet>
      </div>
    );
  }

  // Active interview
  return (
    <div className="flex-1 flex flex-col overflow-hidden" style={{ height: '100dvh', maxHeight: '100dvh' }}>
      {/* Active interview header */}
      <header className="lg:hidden shrink-0 sticky top-0 z-50 bg-background/95 backdrop-blur-sm border-b border-border px-4 py-3">
        <div className="flex items-center gap-3">
          <BackButton onBeforeBack={() => { backTriggeredRef.current = true; setShowEndConfirm(true); return true; }} />
          <Sparkles className="w-5 h-5 text-primary" />
          <h1 className="text-page-title flex-1">Wise AI <span className="text-xs font-normal text-muted-foreground">· Text-only</span></h1>
          <div className="flex items-center gap-1.5 px-3 py-1.5 rounded-full bg-primary/10 border border-primary/25">
            <span className="w-2 h-2 rounded-full bg-primary animate-pulse" />
            <span className="text-xs font-mono font-semibold text-primary tabular-nums">
              {mins}:{secs.toString().padStart(2, '0')}
            </span>
          </div>
        </div>
      </header>

      {/* Progress indicator */}
      {(() => {
        const interviewType = activeInterviewTypeRef.current;
        const currentQuestion = transcript.filter(e => e.role === 'interviewer').length;
        const isQuick = interviewType === 'quick-practice';
        const totalQuestions = 5;
        const progress = isQuick ? Math.min((currentQuestion / totalQuestions) * 100, 100) : 0;
        const totalAnswers = transcript.filter(e => e.role === 'user').length;
        return (
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="px-0">
            <div className="w-full h-[3px] bg-muted/30">
              {isQuick ? (
                <div
                  className="h-full bg-primary rounded-r-full"
                  style={{ width: `${progress}%`, transition: 'width 500ms ease-in-out' }}
                />
              ) : (
                <div
                  className="h-full bg-primary/70 rounded-r-full"
                  style={{ width: `${Math.min(100, totalAnswers * 15)}%`, transition: 'width 500ms ease-in-out' }}
                />
              )}
            </div>
            {isQuick && currentQuestion > 0 && (
              <p className="text-muted-foreground text-xs text-center mt-1">
                Question {Math.min(currentQuestion, totalQuestions)} of {totalQuestions}
              </p>
            )}
            {!isQuick && totalAnswers > 0 && (
              <p className="text-muted-foreground text-xs text-center mt-1">
                {totalAnswers} {totalAnswers === 1 ? 'answer' : 'answers'} · {mins}:{secs.toString().padStart(2, '0')}
              </p>
            )}
          </motion.div>
        );
      })()}

      {/* Transcript area */}
      <div
        ref={scrollRef}
        className="flex-1 min-h-0 overflow-y-auto px-4 py-4 space-y-3 max-w-4xl mx-auto w-full"
      >
        {transcript.map((entry) => (
          <TranscriptBubble key={entry.id} entry={entry} />
        ))}

        {/* Show typing indicator when AI is thinking */}
        <AnimatePresence>
          {status === 'thinking' && <TypingBubble />}
        </AnimatePresence>

        {/* Show error recovery options if AI call failed */}
        <AnimatePresence>
          {status === 'error' && (
            <motion.div
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, scale: 0.9 }}
              className="flex justify-center my-4"
            >
              <div className="flex flex-col items-center gap-3 p-4 bg-destructive/10 border border-destructive/20 rounded-xl text-center max-w-sm w-full">
                <p className="text-sm font-medium text-destructive">Connection failed</p>
                <div className="flex w-full gap-2">
                  <Button variant="outline" size="sm" className="w-full" onClick={skipAITurn}>
                    Skip Turn
                  </Button>
                  <Button variant="default" size="sm" className="w-full bg-destructive text-destructive-foreground hover:bg-destructive/90" onClick={retryAI}>
                    Retry
                  </Button>
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>

      </div>

      {/* Controls */}
      <div className="shrink-0 border-t border-border bg-background/95 backdrop-blur-sm px-4 py-3 space-y-3 pb-safe max-h-[40vh] overflow-y-auto">
        <div className="flex items-center justify-center gap-6 relative">
          {/* Replay button */}
          <motion.button
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            whileTap={{ scale: 1.15 }}
            onClick={() => {
              const lastQ = [...transcript].reverse().find(e => e.role === 'interviewer');
              if (!lastQ) return;
              haptics.light();
              window.speechSynthesis?.cancel();
              const utter = new SpeechSynthesisUtterance(lastQ.text);
              const voices = window.speechSynthesis?.getVoices() ?? [];
              const preferred = voices.find(v => voiceGender === 'female' ? /female|zira|samantha/i.test(v.name) : /male|david|daniel/i.test(v.name));
              if (preferred) utter.voice = preferred;
              window.speechSynthesis?.speak(utter);
            }}
            disabled={status === 'speaking' || status === 'thinking' || !transcript.some(e => e.role === 'interviewer')}
            className="flex flex-col items-center gap-1 min-w-[44px] min-h-[44px] rounded-full text-foreground/70 disabled:opacity-30 active:bg-foreground/10 touch-manipulation transition-opacity"
          >
            <RotateCcw className="w-5 h-5" />
            <span className="text-muted-foreground text-[10px]">Replay</span>
          </motion.button>

          <div className="flex flex-col items-center gap-1 min-w-[44px] min-h-[44px] justify-center">
            <Keyboard className="w-5 h-5 text-muted-foreground" />
            <span className="text-muted-foreground text-[10px]">Type below</span>
          </div>

          {/* Always-visible explicit "I'm done answering" affordance.
              Active when listening so users don't have to wait for the
              silence detector. Disabled in other states with a clear hint. */}
          {(() => {
            const enabled = status === 'listening';
            return (
              <motion.button
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                whileTap={{ scale: enabled ? 0.95 : 1 }}
                onClick={() => {
                  if (!enabled) return;
                  haptics.light();
                  submitAnswerNow();
                }}
                disabled={!enabled}
                aria-label="I'm done answering"
                className="flex flex-col items-center gap-1 min-w-[44px] min-h-[44px] rounded-full text-foreground/80 disabled:opacity-30 active:bg-foreground/10 touch-manipulation transition-opacity"
              >
                <Check className="w-5 h-5" />
                <span className="text-muted-foreground text-[10px]">I'm done</span>
              </motion.button>
            );
          })()}

          {/* Skip button */}
          <motion.button
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            whileTap={{ scale: 1.15 }}
            onClick={() => {
              haptics.light();
              sendTextMessage('(skipped)');
            }}
            disabled={status === 'thinking'}
            className="flex flex-col items-center gap-1 min-w-[44px] min-h-[44px] rounded-full text-foreground/70 disabled:opacity-30 active:bg-foreground/10 touch-manipulation transition-opacity"
          >
            <SkipForward className="w-5 h-5" />
            <span className="text-muted-foreground text-[10px]">Skip</span>
          </motion.button>

        </div>

        {/* Text input fallback */}
        {showTextInput && (
          <motion.div
            initial={{ opacity: 0, height: 0 }}
            animate={{ opacity: 1, height: 'auto' }}
            className="flex gap-2 pt-2"
          >
            <Input
              value={textInput}
              onChange={(e) => setTextInput(e.target.value)}
              placeholder="Type your answer..."
              onKeyDown={(e) => e.key === 'Enter' && handleSendText()}
              disabled={status === 'thinking'}
              className="bg-card border-border"
            />
            <Button
              size="sm"
              onClick={handleSendText}
              disabled={!textInput.trim() || status === 'thinking'}
              className="bg-primary/90 shadow-[0_0_15px_hsl(var(--primary)/0.2)]"
            >
              Send
            </Button>
          </motion.div>
        )}

        <div className="flex items-center justify-between">
          {/* Retry this question — shows after user has answered and AI has responded */}
          {status === 'idle' &&
            transcript.some(e => e.role === 'user') &&
            transcript.length > 0 &&
            transcript[transcript.length - 1].role === 'interviewer' && (
            <Button
              variant="outline"
              size="sm"
              onClick={() => {
                haptics.light();
                retryCurrentQuestion();
              }}
              className="min-h-[44px] text-xs gap-1"
            >
              <RotateCcw className="w-3.5 h-3.5" />
              Retry Question
            </Button>
          )}
          <Button
            variant="destructive"
            size="sm"
            onClick={() => { backTriggeredRef.current = false; setShowEndConfirm(true); }}
            disabled={status === 'thinking'}
            className="shadow-[0_0_15px_hsl(var(--destructive)/0.3)] min-h-[44px]"
          >
            <Square className="w-4 h-4 mr-1" />
            End Interview
          </Button>
        </div>
      </div>

      {/* Per-answer score sheet */}
      <AnswerScoreSheet score={latestScore} onDismiss={dismissScore} />

      {/* Resume previous in-progress interview prompt (within 24h). */}
      <Sheet open={showResumeDraft} onOpenChange={(open) => { if (!open) setDraftDismissed(true); setShowResumeDraft(open); }}>
        <SheetContent side="bottom" hideCloseButton className="px-6 pb-8">
          <SheetTitle className="text-lg font-bold text-foreground text-center">
            Resume previous interview?
          </SheetTitle>
          <SheetDescription className="text-sm text-muted-foreground text-center mt-1">
            We found an unfinished session
            {latestDraft?.job_title ? ` for ${latestDraft.job_title}` : ''}{' '}
            from earlier today. Pick it up where you left off, or start fresh.
          </SheetDescription>
          <div className="flex flex-col gap-3 mt-6">
            <Button
              className="w-full py-3 rounded-xl font-semibold min-h-[48px]"
              onClick={handleResumeDraft}
            >
              Resume Previous
            </Button>
            <Button
              variant="ghost"
              className="w-full py-3 rounded-xl font-medium bg-muted/50 min-h-[48px]"
              onClick={handleDiscardDraft}
            >
              Discard &amp; Start Fresh
            </Button>
          </div>
        </SheetContent>
      </Sheet>

      {/* End interview confirmation sheet */}
      <Sheet open={showEndConfirm} onOpenChange={(open) => { if (!open) backTriggeredRef.current = false; setShowEndConfirm(open); }}>
        <SheetContent side="bottom" hideCloseButton className="px-6 pb-8">
          <SheetTitle className="text-lg font-bold text-foreground text-center">End Interview?</SheetTitle>
          <SheetDescription className="text-sm text-muted-foreground text-center mt-1">
            {user ? "Your progress will be saved and you'll receive your feedback." : "You'll receive your feedback summary."}
          </SheetDescription>
          <div className="flex flex-col gap-3 mt-6">
            <Button
              variant="destructive"
              className="w-full py-3 rounded-xl font-semibold min-h-[48px]"
              onClick={() => {
                setShowEndConfirm(false);
                endInterview();
                if (backTriggeredRef.current) {
                  backTriggeredRef.current = false;
                  navigate(-1);
                }
              }}
            >
              Yes, End Interview
            </Button>
            <Button
              variant="ghost"
              className="w-full py-3 rounded-xl font-medium bg-muted/50 min-h-[48px]"
              onClick={() => {
                setShowEndConfirm(false);
                backTriggeredRef.current = false;
              }}
            >
              Keep Going
            </Button>
          </div>
        </SheetContent>
      </Sheet>
    </div>
  );
}

