  const runTranslation = async (targetLanguage: string, silent = false) => {
    if (!targetLanguage) return null;
    if (!silent) setTranslating(true);
    try {
      const { data, error } = await appwriteFunctions.invoke('generate-portfolio-bio', {
        body: {
          action: 'translate',
          targetLanguage,
          bio,
