import { useEffect, useRef, useMemo } from 'react';
import { BackButton } from '@/components/ui/BackButton';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Copy, Share2, Users, Gift, Star, Linkedin, MessageCircle, ClipboardCopy } from 'lucide-react';
import { useAuth } from '@/hooks/useAuth';
import { toast } from 'sonner';
import { haptics } from '@/lib/haptics';
import { getAppUrl } from '@/lib/portfolioUrl';
import { REFERRAL_REWARDS } from '@/lib/referralData';

export default function ReferralPage() {
  const { user } = useAuth();
  const qrRef = useRef<HTMLDivElement>(null);

  const inviteCode = useMemo(() => {
    if (!user?.id) return 'WISE0000';
    return 'WISE' + user.id.replace(/-/g, '').slice(0, 6).toUpperCase();
  }, [user?.id]);

  const inviteLink = `${getAppUrl()}/?ref=${inviteCode}`;

  // QR code
  useEffect(() => {
    if (!qrRef.current) return;
    let qr: any;
    import('qr-code-styling').then(({ default: QRCodeStyling }) => {
      qr = new QRCodeStyling({
        width: 160,
        height: 160,
        data: inviteLink,
        dotsOptions: { type: 'rounded', color: 'hsl(var(--primary))' },
        backgroundOptions: { color: 'transparent' },
        cornersSquareOptions: { type: 'extra-rounded' },
      });
      if (qrRef.current) {
        qrRef.current.innerHTML = '';
        qr.append(qrRef.current);
      }
    });
    return () => { if (qrRef.current) qrRef.current.innerHTML = ''; };
  }, [inviteLink]);

  const handleCopy = async () => {
    haptics.light();
    try {
      await navigator.clipboard.writeText(inviteLink);
      toast.success('Invite link copied!');
    } catch {
      toast.error('Could not copy link');
    }
  };

  const handleShare = async () => {
    haptics.light();
    if (navigator.share) {
      try {
        await navigator.share({
          title: 'Join WiseResume',
          text: 'Build professional resumes with AI! Use my invite code: ' + inviteCode,
          url: inviteLink,
        });
      } catch { }
    } else {
      handleCopy();
    }
  };

  const handleCopyMessage = async () => {
    haptics.light();
    const message = `Hey! I've been using WiseResume to build AI-powered resumes — it's amazing. Sign up with my invite link and we both get rewards: ${inviteLink}`;
    try {
      await navigator.clipboard.writeText(message);
      toast.success('Message copied!');
    } catch {
      toast.error('Could not copy message');
    }
  };

  const linkedInShareUrl = `https://www.linkedin.com/sharing/share-offsite/?url=${encodeURIComponent(inviteLink)}`;
  const whatsAppShareUrl = `https://wa.me/?text=${encodeURIComponent(`Check out WiseResume — I use it to build AI-powered resumes: ${inviteLink}`)}`;

  return (
    <div className="flex-1 flex flex-col overflow-hidden">
      <header className="pt-safe sticky top-0 z-10 pb-2 px-4 bg-background/95 backdrop-blur-sm border-b border-border">
        <div className="flex items-center gap-3">
          <BackButton />
          <h1 className="text-page-title">Invite Friends</h1>
        </div>
      </header>

      <div className="flex-1 overflow-y-auto px-4 py-4 space-y-6 pb-24 lg:max-w-none mx-auto w-full">
        {/* Invite Code */}
        <Card className="bg-gradient-to-br from-primary/5 to-accent/5">
          <CardContent className="p-6 flex flex-col items-center gap-4">
            <p className="text-sm text-muted-foreground">Your Invite Code</p>
            <div className="text-2xl font-mono font-bold tracking-widest text-primary">{inviteCode}</div>
            <div className="flex gap-2">
              <Button variant="outline" size="sm" onClick={handleCopy} className="gap-2">
                <Copy className="w-4 h-4" />
                Copy Link
              </Button>
              <Button size="sm" onClick={handleShare} className="gap-2">
                <Share2 className="w-4 h-4" />
                Share
              </Button>
            </div>
            <div className="flex gap-2 flex-wrap justify-center">
              <a
                href={linkedInShareUrl}
                target="_blank"
                rel="noopener noreferrer"
                onClick={() => haptics.light()}
                className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium border border-border bg-card hover:bg-muted transition-colors"
              >
                <Linkedin className="w-3.5 h-3.5 text-[#0077B5]" />
                LinkedIn
              </a>
              <a
                href={whatsAppShareUrl}
                target="_blank"
                rel="noopener noreferrer"
                onClick={() => haptics.light()}
                className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium border border-border bg-card hover:bg-muted transition-colors"
              >
                <MessageCircle className="w-3.5 h-3.5 text-[#25D366]" />
                WhatsApp
              </a>
              <button
                onClick={handleCopyMessage}
                className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium border border-border bg-card hover:bg-muted transition-colors"
              >
                <ClipboardCopy className="w-3.5 h-3.5 text-muted-foreground" />
                Copy Message
              </button>
            </div>
          </CardContent>
        </Card>

        {/* QR Code */}
        <Card>
          <CardContent className="p-6 flex flex-col items-center gap-2">
            <p className="text-sm font-medium">Scan to Join</p>
            <div ref={qrRef} className="rounded-xl overflow-hidden" />
          </CardContent>
        </Card>

        {/* Stats (placeholder) */}
        <div className="grid grid-cols-3 gap-3">
          {[
            { label: 'Sent', value: '—', icon: Share2 },
            { label: 'Accepted', value: '—', icon: Users },
            { label: 'Rewards', value: '—', icon: Gift },
          ].map((stat) => (
            <Card key={stat.label}>
              <CardContent className="p-3 flex flex-col items-center gap-1">
                <stat.icon className="w-4 h-4 text-muted-foreground" />
                <p className="text-lg font-bold">{stat.value}</p>
                <p className="text-[10px] text-muted-foreground">{stat.label}</p>
              </CardContent>
            </Card>
          ))}
        </div>
        <p className="text-xs text-muted-foreground mt-2 text-center">Referral tracking coming soon.</p>

        {/* Rewards Tiers */}
        <section>
          <h2 className="text-sm font-semibold text-muted-foreground uppercase tracking-wider mb-3">Rewards</h2>
          <Card>
            <CardContent className="p-0 divide-y divide-border">
              {REFERRAL_REWARDS.map((tier, i) => (
                <div key={i} className="flex items-center gap-3 p-4">
                  <div className="w-8 h-8 rounded-full bg-primary/10 flex items-center justify-center shrink-0">
                    <Star className="w-4 h-4 text-primary" />
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium">{tier.friends} friend{tier.friends > 1 ? 's' : ''}</p>
                    <p className="text-xs text-muted-foreground">{tier.reward}</p>
                  </div>
                </div>
              ))}
            </CardContent>
          </Card>
        </section>
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback, useRef } from 'react';
import { useNavigate, useParams, Navigate } from 'react-router-dom';
import { motion } from 'framer-motion';
import { Copy, Download, Trash2, Save, Sparkles } from 'lucide-react';
import { BackButton } from '@/components/ui/BackButton';
import { MiniSpinner } from '@/components/ui/MiniSpinner';
import { Button } from '@/components/ui/button';
import { Breadcrumb } from '@/components/layout/Breadcrumb';
import { Textarea } from '@/components/ui/textarea';
import { Badge } from '@/components/ui/badge';
import { useResignationLetter, useResignationLetterMutations } from '@/hooks/useResignationLetters';
import { ResignationChecklist } from '@/components/resignation/ResignationChecklist';
import { useAuth } from '@/hooks/useAuth';
import { appwriteFunctions } from '@/lib/appwrite-functions';
import { haptics } from '@/lib/haptics';
import { useQueryClient } from '@tanstack/react-query';
import { invalidateAiCreditQueries } from '@/lib/invalidate-ai-credit-queries';

import { toast } from 'sonner';

import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';

export default function ResignationLetterEditPage() {
  const { id } = useParams<{ id: string }>();
  const navigate = useNavigate();
  const { user, loading: authLoading } = useAuth();
  const { data: letter, isLoading } = useResignationLetter(id || null);
  const { updateLetter, deleteLetter } = useResignationLetterMutations();
  const queryClient = useQueryClient();

  const [content, setContent] = useState('');
  const [isEditing, setIsEditing] = useState(false);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState(false);
  const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);
  const [regenerating, setRegenerating] = useState(false);
  const [checklistProgress, setChecklistProgress] = useState<string[]>([]);
  const saveTimeoutRef = useRef<NodeJS.Timeout | null>(null);

  useEffect(() => {
    if (letter) {
      setContent(letter.content);
      setChecklistProgress(Array.isArray(letter.checklist_progress) ? letter.checklist_progress : []);
    }
  }, [letter]);

  const handleContentChange = useCallback((newContent: string) => {
    setContent(newContent);
    setHasUnsavedChanges(true);
    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    saveTimeoutRef.current = setTimeout(() => {
      if (id) {
        updateLetter.mutate({ id, content: newContent } as any);
        setHasUnsavedChanges(false);
      }
    }, 2000);
  }, [id, updateLetter]);

  const handleSave = useCallback(() => {
    if (!id || !content.trim()) return;
    if (saveTimeoutRef.current) clearTimeout(saveTimeoutRef.current);
    updateLetter.mutate({ id, content } as any);
    setHasUnsavedChanges(false);
    haptics.light();
    toast.success('Saved');
  }, [id, content, updateLetter]);

  const handleCopy = useCallback(async () => {
    await navigator.clipboard.writeText(content);
    haptics.light();
    toast.success('Copied to clipboard');
  }, [content]);

  const handleDownloadPDF = useCallback(async () => {
    if (!content) return;
    try {
      const { PDFDocument, StandardFonts, rgb } = await import('pdf-lib');
      const pdfDoc = await PDFDocument.create();
      const font = await pdfDoc.embedFont(StandardFonts.Helvetica);
      const fontSize = 11;
      const margin = 72;
      const pw = 612;
      const ph = 792;
      const maxW = pw - margin * 2;
      const lh = fontSize * 1.5;

      const lines: string[] = [];
      for (const para of content.split('\n')) {
        if (!para.trim()) { lines.push(''); continue; }
        const words = para.split(/\s+/);
        let cur = '';
        for (const w of words) {
          const test = cur ? `${cur} ${w}` : w;
          if (font.widthOfTextAtSize(test, fontSize) > maxW && cur) { lines.push(cur); cur = w; }
          else cur = test;
        }
        if (cur) lines.push(cur);
      }

      let page = pdfDoc.addPage([pw, ph]);
      let y = ph - margin;
      for (const line of lines) {
        if (y < margin) { page = pdfDoc.addPage([pw, ph]); y = ph - margin; }
        if (line) page.drawText(line, { x: margin, y, size: fontSize, font, color: rgb(0.1, 0.1, 0.1) });
        y -= lh;
      }

      const bytes = await pdfDoc.save();
      const blob = new Blob([bytes.buffer as ArrayBuffer], { type: 'application/pdf' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `resignation-letter-${letter?.company || 'untitled'}.pdf`;
      a.click();
      URL.revokeObjectURL(url);
      toast.success('PDF downloaded!');
    } catch {
      toast.error('Failed to generate PDF');
    }
  }, [content, letter?.company]);

  const handleRegenerate = useCallback(async () => {
    if (!letter) return;
    setRegenerating(true);
    try {
      const { data, error } = await appwriteFunctions.invoke('generate-resignation-letter', {
        body: {
          recipientName: letter.recipient_name,
          company: letter.company,
          position: letter.position,
          lastWorkingDay: letter.last_working_day,
          noticePeriod: letter.notice_period,
          reason: letter.reason,
          tone: letter.tone,
          templateStyle: letter.template_style,
          additions: Array.isArray(letter.additions) ? letter.additions : [],
        },
      });

      if (error) throw new Error(error.message || 'Failed to regenerate');
      if (data?.error) throw new Error(data.error || 'Failed to regenerate');
      invalidateAiCreditQueries(queryClient);
      setContent(data.letter);
      setHasUnsavedChanges(true);
      haptics.success();
      toast.success('Letter regenerated!');
    } catch {
      toast.error('Failed to regenerate letter');
    } finally {
      setRegenerating(false);
    }
  }, [letter]);

  const handleChecklistToggle = useCallback((itemId: string) => {
    setChecklistProgress(prev => {
      const next = prev.includes(itemId) ? prev.filter(i => i !== itemId) : [...prev, itemId];
      if (id) {
        updateLetter.mutate({ id, checklist_progress: next } as any);
      }
      return next;
    });
  }, [id, updateLetter]);

  const handleDelete = useCallback(() => {
    if (!id) return;
    haptics.warning();
    deleteLetter.mutate(id, {
      onSuccess: () => navigate('/resignation-letters', { replace: true }),
    });
  }, [id, deleteLetter, navigate]);

  // Auth guard handled by ProtectedRoute
  // Suspense fallback already shows DetailSkeleton; avoid double skeleton
  if (isLoading || authLoading) return null;
  if (!letter) {
    return (
      <div className="flex-1 flex items-center justify-center p-4">
        <p className="text-muted-foreground">Resignation letter not found</p>
      </div>
    );
  }

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="flex-1 flex flex-col min-h-0 overflow-hidden">
      <header className="sticky top-0 z-10 bg-background/95 backdrop-blur-sm border-b border-border px-4 py-3 space-y-1">
        <div className="flex items-center gap-3">
          <BackButton />
          <div className="flex-1 min-w-0">
            <h1 className="text-base font-bold truncate">{letter.title || `${letter.company} Resignation`}</h1>
            <div className="flex items-center gap-2">
              {letter.company && <span className="text-xs text-muted-foreground truncate">{letter.company}</span>}
              <Badge variant="secondary" className="text-[10px] px-1.5 py-0 h-4 capitalize">{letter.tone}</Badge>
              {hasUnsavedChanges && <span className="text-[10px] text-warning">Unsaved</span>}
            </div>
          </div>
          <Button variant="ghost" size="sm" onClick={() => setIsEditing(!isEditing)} className="touch-manipulation">
            {isEditing ? 'Preview' : 'Edit'}
          </Button>
        </div>
        <Breadcrumb items={['AI Tools', 'Resignation Letters', 'Edit']} className="pl-10" />
      </header>

      <div className="flex-1 overflow-y-auto overscroll-y-contain">
        <div className="px-4 pt-4 pb-32 space-y-6">
          {isEditing ? (
            <Textarea
              value={content}
              onChange={(e) => handleContentChange(e.target.value)}
              className="min-h-[60vh] text-[15px] leading-relaxed"
              autoFocus
            />
          ) : (
            <div className="bg-card border border-border shadow-soft rounded-2xl p-5 text-sm whitespace-pre-wrap leading-relaxed min-h-[40vh]">
              {content}
            </div>
          )}

          {/* Resignation Checklist */}
          <ResignationChecklist
            completedItems={checklistProgress}
            onToggle={handleChecklistToggle}
          />
        </div>
      </div>

      {/* Bottom Toolbar */}
      <div className="fixed bottom-[calc(4rem+env(safe-area-inset-bottom))] lg:bottom-0 left-0 right-0 z-40 px-4 lg:px-6 lg:pb-4">
        <div className="bg-background/95 backdrop-blur-sm border border-border rounded-2xl p-2.5 flex gap-1.5 shadow-lg">
          <Button variant="outline" size="sm" className="gap-1 flex-1 h-10" onClick={handleSave}>
            <Save className="w-4 h-4" /> Save
          </Button>
          <Button variant="outline" size="sm" className="gap-1 flex-1 h-10" onClick={handleCopy}>
            <Copy className="w-4 h-4" /> Copy
          </Button>
          <Button variant="outline" size="sm" className="gap-1 flex-1 h-10" onClick={handleDownloadPDF}>
            <Download className="w-4 h-4" /> PDF
          </Button>
          <Button variant="outline" size="sm" className="gap-1 h-10" onClick={handleRegenerate} disabled={regenerating}>
            {regenerating ? <MiniSpinner size={16} /> : <Sparkles className="w-4 h-4" />}
          </Button>
          <Button variant="outline" size="sm" className="gap-1 h-10 text-destructive" onClick={() => setShowDeleteConfirm(true)}>
            <Trash2 className="w-4 h-4" />
          </Button>
        </div>
      </div>

      <AlertDialog open={showDeleteConfirm} onOpenChange={setShowDeleteConfirm}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Resignation Letter?</AlertDialogTitle>
            <AlertDialogDescription>This action cannot be undone.</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete} className="bg-destructive text-destructive-foreground">
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </motion.div>
  );
}

import { useState, useRef, useEffect, lazy, Suspense } from 'react';
import { useNavigate, useParams, useSearchParams } from 'react-router-dom';
import { useQueryClient } from '@tanstack/react-query';
import { Edit2, Eye, Download, Share2, Copy, Trash2, GitBranch, Crown, Zap, BarChart3, RefreshCw, Mic, MoreVertical, Sparkles } from 'lucide-react';
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from '@/components/ui/dropdown-menu';
import { BackButton } from '@/components/ui/BackButton';
import { Breadcrumb } from '@/components/layout/Breadcrumb';
import { MiniSpinner } from '@/components/ui/MiniSpinner';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import { TemplateThumbnail } from '@/components/editor/TemplateThumbnail';
import { templateComponents } from '@/components/editor/TemplateThumbnail';
import { ScoreRing } from '@/components/dashboard/ScoreRing';
import { useResume, useResumes, useResumeMutations, dbToResumeData } from '@/hooks/useResumes';
import { useResumeScore, clearCachedScore } from '@/hooks/useResumeScore';
import { useResumeStore } from '@/store/resumeStore';
import { templates } from '@/lib/templateData';
import { safeFormatDistanceToNow } from '@/lib/dateUtils';
import { useResumeShareMutations } from '@/hooks/useResumeShares';
import { toast } from 'sonner';
import { TemplateId } from '@/types/resume';
import { calcOverallScore, calcContactScore, calcSummaryScore, calcExperienceScore, calcEducationScore, calcSkillsScore, getSectionStatus } from '@/lib/resumeCompletionRules';
import { ProgressBar } from '@/components/editor/ProgressBar';
import { ErrorBoundary } from '@/components/ErrorBoundary';
import { useATSScoreHistoryStore } from '@/store/atsScoreHistoryStore';
import { Collapsible, CollapsibleTrigger, CollapsibleContent } from '@/components/ui/collapsible';
import { Card, CardContent } from '@/components/ui/card';
import { lazyWithRetry } from '@/lib/lazyWithRetry';
import { ChevronDown } from 'lucide-react';

const ATSScoreTrendChart = lazyWithRetry(() => import('@/components/dashboard/ATSScoreTrendChart').then(m => ({ default: m.ATSScoreTrendChart })));

const AIEnhanceSheet = lazy(() => import('@/components/editor/ai/AIEnhanceSheet').then(m => ({ default: m.AIEnhanceSheet })));

export default function ResumeDetailPage() {
  const { id } = useParams<{ id: string }>();
  const [searchParams, setSearchParams] = useSearchParams();
  const navigate = useNavigate();
  const { data: dbResume, isLoading } = useResume(id || null);
  const { data: allResumes = [] } = useResumes();
  const { deleteResume, duplicateResume } = useResumeMutations();
  const { setCurrentResume, setCurrentResumeId, setSelectedTemplate } = useResumeStore();
  const { getCachedScore, getLatestCachedScore, scoreResume, scoringId } = useResumeScore();
  const { createShare } = useResumeShareMutations();
  const { updateResume } = useResumeMutations();
  const queryClient = useQueryClient();
  const scoreHistory = useATSScoreHistoryStore(s => id ? s.getHistory(id) : []);
  const [deleteOpen, setDeleteOpen] = useState(false);
  const [isDownloading, setIsDownloading] = useState(false);
  const [showEnhance, setShowEnhance] = useState(false);
  const [improvedSections, setImprovedSections] = useState<Set<string>>(new Set());
  const [latestScore, setLatestScore] = useState<ReturnType<typeof getCachedScore>>(null);
  const enhancedRef = useRef(false);
  const enhancedSectionsRef = useRef<string[]>([]);
  const prevScoreRef = useRef<ReturnType<typeof getCachedScore>>(null);
  const hiddenTemplateRef = useRef<HTMLDivElement>(null);

  // Redirect download action to Preview page for proper page break handling
  // Reset locally-tracked score when navigating between resumes so the
  // previous resume's score never bleeds into a new one before its cache
  // entry lands.
  useEffect(() => {
    setLatestScore(null);
  }, [dbResume?.id]);

  useEffect(() => {
    if (searchParams.get('action') !== 'download' || !dbResume || isLoading) return;
    searchParams.delete('action');
    setSearchParams(searchParams, { replace: true });
    // Load resume into store and redirect to preview
    const rd = dbToResumeData(dbResume);
    setCurrentResume(rd);
    setCurrentResumeId(dbResume.$id);
    setSelectedTemplate(dbResume.template_id as TemplateId);
    navigate('/preview?action=download', { replace: true });
  }, [dbResume, isLoading]);

  if (isLoading) {
    return (
      <div className="flex-1 flex items-center justify-center">
        <MiniSpinner size={32} className="text-primary" />
      </div>
    );
  }

  if (!dbResume) {
    return (
      <div className="flex-1 flex flex-col items-center justify-center px-6 text-center">
        <h2 className="text-xl font-bold text-foreground mb-2">Resume not found</h2>
        <p className="text-muted-foreground mb-4">This resume may have been deleted.</p>
        <Button onClick={() => navigate('/dashboard')}>Go to Dashboard</Button>
      </div>
    );
  }

  const resumeData = dbToResumeData(dbResume);
  const templateInfo = templates.find(t => t.id === dbResume.template_id);
  const healthScore = getCachedScore(dbResume.id, dbResume.updated_at) ?? latestScore ?? getLatestCachedScore(dbResume.id);
  
  const isTailored = !!dbResume.parent_resume_id;
  const isMaster = !!dbResume.is_primary;

  // Quick stats
  const completionScore = calcOverallScore(resumeData);
  const sectionScores = [
    calcContactScore(resumeData.contactInfo),
    calcSummaryScore(resumeData.summary),
    calcExperienceScore(resumeData.experience),
    calcEducationScore(resumeData.education),
    calcSkillsScore(resumeData.skills),
  ];
  const completedSections = sectionScores.filter(s => getSectionStatus(s) === 'complete').length;
  const totalSections = sectionScores.length;
  const tailoredCount = allResumes.filter(r => r.parent_resume_id === dbResume.id).length;

  const handleEdit = () => {
    setCurrentResume(resumeData);
    setCurrentResumeId(dbResume.$id);
    setSelectedTemplate(dbResume.template_id as TemplateId);
    navigate('/editor');
  };

  const handlePreview = () => {
    setCurrentResume(resumeData);
    setCurrentResumeId(dbResume.$id);
    setSelectedTemplate(dbResume.template_id as TemplateId);
    navigate('/preview');
  };

  const handleDownload = () => {
    // Redirect all downloads to Preview page for proper page break handling
    setCurrentResume(resumeData);
    setCurrentResumeId(dbResume.$id);
    setSelectedTemplate(dbResume.template_id as TemplateId);
    navigate('/preview?action=download');
  };



  const handleDuplicate = () => {
    duplicateResume.mutate(dbResume.id, {
      onSuccess: () => navigate('/dashboard'),
    });
  };

  const handleDelete = () => {
    deleteResume.mutate(dbResume.id, {
      onSuccess: () => navigate('/dashboard'),
    });
  };

  const handleTailor = () => {
    setCurrentResume(resumeData);
    setCurrentResumeId(dbResume.$id);
    setSelectedTemplate(dbResume.template_id as TemplateId);
    navigate('/editor?openTailor=1');
  };

  const handleInterview = () => {
    setCurrentResume(resumeData);
    setCurrentResumeId(dbResume.$id);
    navigate('/interview');
  };



  return (
    <div className="flex-1 flex flex-col min-h-0">
      {/* Header with overflow menu */}
      <div className="shrink-0 sticky top-0 z-30 flex items-center gap-3 px-4 h-14 pt-safe border-b border-border bg-background/95 backdrop-blur-sm">
        <BackButton />
        <div className="flex flex-col min-w-0 flex-1">
          <h1 className="text-lg font-bold text-foreground truncate">{dbResume.title}</h1>
          <Breadcrumb items={['Home', dbResume.title]} links={['/dashboard']} />
        </div>
        {isMaster && (
          <Badge variant="outline" className="text-[10px] px-1.5 py-0 h-5 gap-1 border-primary/30 text-primary shrink-0">
            <Crown className="w-3 h-3" />
            <span className="hidden sm:inline">Master</span>
          </Badge>
        )}
        {isTailored && (
          <Badge variant="secondary" className="hidden sm:flex text-[10px] px-1.5 py-0 h-5 gap-1 shrink-0">
            <GitBranch className="w-3 h-3" />
            Tailored
          </Badge>
        )}
        {tailoredCount > 0 && !isTailored && (
          <Badge variant="secondary" className="hidden sm:flex text-[10px] px-1.5 py-0 h-5 shrink-0">
            {tailoredCount} tailored
          </Badge>
        )}
        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <button className="p-2 -mr-2 rounded-xl hover:bg-muted/50 min-h-[44px] min-w-[44px] flex items-center justify-center" aria-label="More options">
              <MoreVertical className="w-5 h-5 text-muted-foreground" />
            </button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            <DropdownMenuItem onClick={handleDuplicate}>
              <Copy className="w-4 h-4 mr-2" /> Duplicate
            </DropdownMenuItem>
            <DropdownMenuItem onClick={() => {
              createShare.mutate({ resumeId: dbResume.id }, {
                onSuccess: (data) => {
                  const url = `${window.location.origin}/share/${data.token}`;
                  navigator.clipboard.writeText(url);
                  toast.success('Share link copied!');
                },
              });
            }}>
              <Share2 className="w-4 h-4 mr-2" /> Share Link
            </DropdownMenuItem>
            <DropdownMenuItem onClick={() => setDeleteOpen(true)} className="text-destructive focus:text-destructive">
              <Trash2 className="w-4 h-4 mr-2" /> Delete
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      </div>

      <div className="flex-1 overflow-y-auto px-4 py-4 space-y-4 lg:max-w-none mx-auto w-full">
        {/* Mobile-only badge row — secondary badges hidden from header on small screens */}
        {(isTailored || (tailoredCount > 0 && !isTailored)) && (
          <div className="flex sm:hidden flex-wrap gap-2">
            {isTailored && (
              <Badge variant="secondary" className="text-[10px] px-1.5 py-0 h-5 gap-1">
                <GitBranch className="w-3 h-3" />
                Tailored
              </Badge>
            )}
            {tailoredCount > 0 && !isTailored && (
              <Badge variant="secondary" className="text-[10px] px-1.5 py-0 h-5">
                {tailoredCount} tailored
              </Badge>
            )}
          </div>
        )}
        {/* Tailored Context */}
        {isTailored && (dbResume.target_job_title || dbResume.target_company) && (
          <div className="bg-card border border-primary/20 shadow-soft rounded-2xl p-4">
            <p className="text-xs font-medium text-muted-foreground mb-1">Tailored for</p>
            <p className="text-sm font-semibold text-foreground">
              {dbResume.target_job_title}
              {dbResume.target_company ? ` @ ${dbResume.target_company}` : ''}
            </p>
            <button
              onClick={() => navigate(`/resume/${dbResume.parent_resume_id}`)}
              className="text-xs text-primary mt-2 hover:underline"
            >
              ← View Original Resume
            </button>
          </div>
        )}

        {/* Hero Card: Thumbnail + ATS + Meta + Progress + Actions */}
        <div className="bg-card border border-border shadow-soft rounded-2xl p-4 space-y-4">
          {/* Top row: thumbnail + score + meta */}
          <div className="flex gap-4">
            <div className="w-[100px] shrink-0 rounded-xl overflow-hidden border border-border shadow-sm">
              <TemplateThumbnail templateId={dbResume.template_id as TemplateId} resume={resumeData} />
            </div>

            <div className="flex-1 min-w-0 flex flex-col justify-between">
              <div className="flex items-start gap-3">
                <div className="flex flex-col items-center gap-1">
                  {healthScore ? (
                    <>
                      <ScoreRing score={healthScore.overallScore} size={56} strokeWidth={4} />
                      <span className="text-[10px] font-semibold text-muted-foreground">ATS</span>
                    </>
                  ) : (
                    <button
                      onClick={() => {
                      scoreResume(dbResume.id, resumeData, dbResume.updated_at).then(s => { if (s) setLatestScore(s); });
                    }}
                      disabled={scoringId === dbResume.id}
                      className="flex flex-col items-center gap-1"
                      aria-label="Score resume"
                    >
                      <div className="w-14 h-14 rounded-full border-2 border-dashed border-muted-foreground/30 flex items-center justify-center">
                        {scoringId === dbResume.id ? <MiniSpinner size={20} /> : <BarChart3 className="w-5 h-5 text-muted-foreground/50" />}
                      </div>
                      <span className="text-[10px] text-muted-foreground">Score</span>
                    </button>
                  )}
                </div>

                <div className="flex-1 min-w-0 space-y-1">
                  <Badge variant="secondary" className="text-[10px] px-1.5 py-0 h-5">{templateInfo?.name || dbResume.template_id}</Badge>
                  <p className="text-xs text-muted-foreground">
                    {completedSections}/{totalSections} sections · {completionScore}%
                  </p>
                  <p className="text-[11px] text-muted-foreground/70">
                    Edited {safeFormatDistanceToNow(dbResume.updated_at, { addSuffix: true })}
                  </p>
                </div>
              </div>

              {healthScore && (
                <div className="flex gap-2 mt-2">
                  <Button
                    variant="ghost"
                    size="sm"
                    className="h-8 px-2.5 text-xs gap-1.5"
                    disabled={scoringId === dbResume.id}
                    onClick={() => {
                      clearCachedScore(dbResume.id, dbResume.updated_at);
                      setLatestScore(null);
                      scoreResume(dbResume.id, resumeData, dbResume.updated_at, true).then(s => { if (s) setLatestScore(s); });
                    }}
                  >
                    {scoringId === dbResume.id ? <MiniSpinner size={14} /> : <RefreshCw className="w-3.5 h-3.5" />}
                    Re-score
                  </Button>
                  <Button
                    size="sm"
                    className="h-8 px-2.5 text-xs gap-1.5"
                    onClick={() => {
                      setCurrentResume(resumeData);
                      setCurrentResumeId(dbResume.$id);
                      setSelectedTemplate(dbResume.template_id as TemplateId);
                      prevScoreRef.current = getCachedScore(dbResume.id, dbResume.updated_at);
                      enhancedRef.current = false;
                      enhancedSectionsRef.current = [];
                      setShowEnhance(true);
                    }}
                  >
                    <Zap className="w-3.5 h-3.5" />
                    Improve
                  </Button>
                </div>
              )}
            </div>
          </div>

          {/* Inline Progress */}
          <ProgressBar resume={resumeData} compact />

          {/* Primary CTA */}
          <Button className="w-full gap-2 min-h-[48px] active:scale-[0.98] transition-transform text-base" onClick={handleEdit}>
            <Edit2 className="w-4.5 h-4.5" /> Edit Resume
          </Button>

          {/* Secondary actions */}
          <div className="flex gap-2">
            <Button variant="outline" className="flex-1 gap-2 min-h-[44px] active:scale-[0.98] transition-transform" onClick={handlePreview}>
              <Eye className="w-4 h-4" /> Preview & Export
            </Button>
            <Button variant="outline" className="flex-1 gap-2 min-h-[44px] active:scale-[0.98] transition-transform" onClick={handleDownload} disabled={isDownloading}>
              {isDownloading ? <MiniSpinner size={16} /> : <Download className="w-4 h-4" />} Download PDF
            </Button>
          </div>
        </div>

        {/* Score History (collapsible) */}
        {scoreHistory.length >= 2 && (
          <Collapsible>
            <Card>
              <CollapsibleTrigger className="w-full flex items-center justify-between p-4">
                <span className="text-sm font-semibold text-foreground">Score History</span>
                <ChevronDown className="w-4 h-4 text-muted-foreground transition-transform [[data-state=open]>svg&]:rotate-180" />
              </CollapsibleTrigger>
              <CollapsibleContent>
                <CardContent className="pt-0">
                  <Suspense fallback={<div className="h-[200px] bg-muted animate-pulse rounded-xl" />}>
                    <ATSScoreTrendChart history={scoreHistory} mode="full" />
                  </Suspense>
                </CardContent>
              </CollapsibleContent>
            </Card>
          </Collapsible>
        )}

        {/* AI Tools */}
        <div className="space-y-2">
          <p className="text-xs font-medium text-muted-foreground px-1">AI Tools</p>
          <div className="grid grid-cols-2 gap-2">
            <button
              onClick={handleTailor}
              className="flex items-center gap-3 p-3.5 rounded-2xl bg-card hover:border-primary/30 border border-border shadow-soft-sm transition-all touch-manipulation active:scale-[0.98] min-h-[56px]"
              aria-label="Tailor resume"
            >
              <div className="w-9 h-9 rounded-xl bg-primary/10 flex items-center justify-center shrink-0">
                <Sparkles className="w-4.5 h-4.5 text-primary" />
              </div>
              <div className="text-left min-w-0">
                <p className="text-sm font-medium text-foreground">Tailor</p>
                <p className="text-[11px] text-muted-foreground truncate">Customize for a job</p>
              </div>
            </button>

            <button
              onClick={handleInterview}
              className="flex items-center gap-3 p-3.5 rounded-2xl bg-card hover:border-primary/30 border border-border shadow-soft-sm transition-all touch-manipulation active:scale-[0.98] min-h-[56px]"
              aria-label="Interview prep"
            >
              <div className="w-9 h-9 rounded-xl bg-primary/10 flex items-center justify-center shrink-0">
                <Mic className="w-4.5 h-4.5 text-primary" />
              </div>
              <div className="text-left min-w-0">
                <p className="text-sm font-medium text-foreground">Interview</p>
                <p className="text-[11px] text-muted-foreground truncate">Practice questions</p>
              </div>
            </button>
          </div>
        </div>
      </div>

      {/* Delete Confirmation */}
      <AlertDialog open={deleteOpen} onOpenChange={setDeleteOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Resume</AlertDialogTitle>
            <AlertDialogDescription>
              This will permanently delete "{dbResume.title}". This action cannot be undone.
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete} className="bg-destructive text-destructive-foreground hover:bg-destructive/90">
              Delete
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>

      {/* AI Enhance Sheet (inline, no navigation) */}
      <ErrorBoundary>
        <Suspense fallback={null}>
          {showEnhance && (
            <AIEnhanceSheet
              open={showEnhance}
              atsMode
              disabledSections={improvedSections}
              onEnhanced={(sections) => {
                enhancedRef.current = true;
                if (sections) {
                  enhancedSectionsRef.current = [
                    ...enhancedSectionsRef.current,
                    ...sections,
                  ];
                }
              }}
              onOpenChange={(open) => {
                if (!open && !enhancedRef.current) {
                  // Closed without changes — just close, zero API calls
                  setShowEnhance(false);
                  return;
                }

                setShowEnhance(open);

                if (!open && enhancedRef.current) {
                  // Track which sections were improved to block re-optimization
                  setImprovedSections(prev => {
                    const next = new Set(prev);
                    enhancedSectionsRef.current.forEach(s => next.add(s));
                    return next;
                  });

                  // Save enhanced data to the database
                  const updatedResume = useResumeStore.getState().currentResume;
                  if (updatedResume) {
                    updateResume.mutate(
                      { resumeId: dbResume.id, updates: updatedResume },
                      {
                        onSuccess: () => {
                          queryClient.invalidateQueries({ queryKey: ['resume', id] });
                          // Re-score with force flag — old score stays visible until new one arrives.
                          // Capture the result into local state so the UI re-renders even after the
                          // resume query refetches (which changes updated_at and invalidates the
                          // cache key the new score was stored under).
                          scoreResume(dbResume.id, updatedResume, dbResume.updated_at, true)
                            .then(s => { if (s) setLatestScore(s); });
                        },
                      }
                    );
                  }
                }
              }}
            />
          )}
        </Suspense>
      </ErrorBoundary>

      {/* Hidden off-screen template for PDF generation */}
      {(() => {
        const TemplateComponent = templateComponents[dbResume.template_id as TemplateId];
        return TemplateComponent ? (
          <div
            ref={hiddenTemplateRef}
            data-resume-template
            style={{
              position: 'fixed',
              left: '-9999px',
              top: 0,
            width: '612px',
            minHeight: '792px',
            transform: 'scale(1)',
            transformOrigin: 'top left',
            overflow: 'visible',
            }}
          >
            <Suspense fallback={null}>
              <TemplateComponent resume={resumeData} />
            </Suspense>
          </div>
        ) : null;
      })()}
    </div>
  );
}

import { useEffect, useState, useCallback, useRef, lazy, Suspense } from 'react';
import { getAppUrl } from '@/lib/portfolioUrl';
