function buildPlainText(resume: ResumeData, tailorResult: SuperTailorResult, enabledSections: TailorSectionId[]): string {
  const lines: string[] = [];
  const ci = resume.contactInfo;
  lines.push(ci.fullName || '');
  const contact = [ci.email, ci.phone, ci.location].filter(Boolean).join(' | ');
  if (contact) lines.push(contact);
  lines.push('');

  if (enabledSections.includes('summary') && tailorResult.summary) {
    lines.push('SUMMARY');
    lines.push(tailorResult.summary);
    lines.push('');
  }

  const skills = enabledSections.includes('skills') ? tailorResult.skills : resume.skills;
  if (skills.length > 0) {
    lines.push('SKILLS');
    lines.push(skills.join(', '));
    lines.push('');
  }

  const experiences = enabledSections.includes('experience') ? tailorResult.experience : resume.experience;
  if (experiences.length > 0) {
    lines.push('EXPERIENCE');
    for (const exp of experiences) {
      lines.push(`${exp.position} | ${exp.company}`);
      lines.push(`${exp.startDate} – ${exp.current ? 'Present' : exp.endDate}`);
      if (exp.description) lines.push(exp.description);
      for (const ach of (exp.achievements || [])) {
        lines.push(`• ${ach}`);
      }
      lines.push('');
    }
  }

  const educations = enabledSections.includes('education') ? tailorResult.education : resume.education;
  if (educations.length > 0) {
    lines.push('EDUCATION');
    for (const edu of educations) {
      lines.push(`${formatDegreeAndField(edu.degree, edu.field)} | ${edu.institution}`);
      lines.push(`${edu.startDate} – ${edu.endDate}`);
      if (edu.description) lines.push(edu.description);
      lines.push('');
    }
  }

  const projects = enabledSections.includes('projects') ? (tailorResult.projects ?? resume.projects) : resume.projects;
  if (projects && projects.length > 0) {
    lines.push('PROJECTS');
    for (const p of projects) {
      lines.push(`${p.name}${p.role ? ` | ${p.role}` : ''}`);
      if (p.technologies?.length) lines.push(`Technologies: ${p.technologies.join(', ')}`);
      if (p.description) lines.push(p.description);
      lines.push('');
    }
  }

  const certifications = enabledSections.includes('certifications') ? (tailorResult.certifications ?? resume.certifications) : resume.certifications;
  if (certifications && certifications.length > 0) {
    lines.push('CERTIFICATIONS');
    for (const c of certifications) {
      lines.push(`${c.name} | ${c.issuer}${c.date ? ` | ${c.date}` : ''}`);
    }
    lines.push('');
  }

  const awards = enabledSections.includes('awards') ? (tailorResult.awards ?? resume.awards) : resume.awards;
  if (awards && awards.length > 0) {
    lines.push('AWARDS');
    for (const a of awards) {
      lines.push(`${a.title} | ${a.issuer}${a.date ? ` | ${a.date}` : ''}`);
      if (a.description) lines.push(a.description);
    }
    lines.push('');
  }

  return lines.join('\n').trim();
}

export default function TailorPage() {
  const navigate = useNavigate();
  const { resumeId: paramResumeId } = useParams<{ resumeId?: string }>();
  const [searchParams] = useSearchParams();
  const { user } = useAuth();

  const {
    currentResumeId,
    jobDescription,
    setJobDescription,
    addTailorHistory,
    setPendingTailor,
    clearPendingTailor,
    setCurrentResumeId,
    pendingTailorResult,
    pendingTailorOriginal,
    pendingTailorJobInfo,
    pendingTailorIntensity,
    pendingTailorJobUrl,
    pendingTailorSections,
  } = useResumeStore(useShallow(state => ({
    currentResumeId: state.currentResumeId,
    jobDescription: state.jobDescription,
    setJobDescription: state.setJobDescription,
    addTailorHistory: state.addTailorHistory,
    setPendingTailor: state.setPendingTailor,
    clearPendingTailor: state.clearPendingTailor,
    setCurrentResumeId: state.setCurrentResumeId,
    pendingTailorResult: state.pendingTailorResult,
    pendingTailorOriginal: state.pendingTailorOriginal,
    pendingTailorJobInfo: state.pendingTailorJobInfo,
    pendingTailorIntensity: state.pendingTailorIntensity,
    pendingTailorJobUrl: state.pendingTailorJobUrl,
    pendingTailorSections: state.pendingTailorSections,
  })));

  const { data: allResumes } = useResumes();

  const currentResume = useMemo(() => {
    const found = allResumes?.find((r: DatabaseResume) => r.id === currentResumeId);
    return found ? dbToResumeData(found) : null;
  }, [allResumes, currentResumeId]);
  const selectedResumeTitle = useMemo(() => {
    const found = allResumes?.find((r: DatabaseResume) => r.id === currentResumeId);
    return found?.title ?? '';
  }, [allResumes, currentResumeId]);

  const [isTailoring, setIsTailoring] = useState(false);
  const [tailorResult, setTailorResult] = useState<SuperTailorResult | null>(null);
  const [originalResume, setOriginalResume] = useState<ResumeData | null>(null);
  const [progress, setProgress] = useState<TailorProgress | EnhancedTailorProgress | null>(null);
  const [parsedJobInfo, setParsedJobInfo] = useState<{ title: string; company: string } | null>(null);
  const [intensity, setIntensity] = useState<TailorIntensity>('moderate');
  const [wizardStep, setWizardStep] = useState<TailorFlowStep>('resume');
  const [isApplying, setIsApplying] = useState(false);
  const [jobUrl, setJobUrl] = useState<string | undefined>(undefined);
  const [tailorError, setTailorError] = useState<{ message: string; code?: string } | null>(null);
  const [copiedText, setCopiedText] = useState(false);
  const [showAppliedCTA, setShowAppliedCTA] = useState(false);
  const [showTailorPreview, setShowTailorPreview] = useState(false);
  const [appliedResumeId, setAppliedResumeId] = useState<string | null>(null);
  const [appliedResumeTitle, setAppliedResumeTitle] = useState<string | null>(null);
  const [appliedJobInfo, setAppliedJobInfo] = useState<{ title: string; company: string } | null>(null);
  const [appliedScore, setAppliedScore] = useState<{ before: number; after: number } | null>(null);
  const [appliedKeywordCount, setAppliedKeywordCount] = useState<number | null>(null);
  const [appliedValidatorResult, setAppliedValidatorResult] = useState<ValidatorResult | null>(null);

  const [preValidatorResult, setPreValidatorResult] = useState<ValidatorResult | null>(null);
  const [isPreValidating, setIsPreValidating] = useState(false);
  const [dismissedIssueIndices, setDismissedIssueIndices] = useState<Set<number>>(new Set());
  const [fixSuggestions, setFixSuggestions] = useState<FixSuggestion[] | null>(null);
  const [isGeneratingFixes, setIsGeneratingFixes] = useState(false);
  const [appliedFixes, setAppliedFixes] = useState<FixSuggestion[]>([]);

  const [customInstructions, setCustomInstructions] = useState(
    () => localStorage.getItem(CUSTOM_INSTRUCTIONS_KEY) || ''
  );
  const [showCustomInstructions, setShowCustomInstructions] = useState(false);

  const [enabledSections, setEnabledSections] = useState<TailorSectionId[]>([
    'summary', 'skills', 'experience', 'education', 'projects', 'certifications', 'awards'
  ]);
  const [revealedSections, setRevealedSections] = useState<Set<TailorSectionId>>(new Set());
  const [rejectedBullets, setRejectedBullets] = useState<Set<string>>(new Set());

  const abortRef = useRef<AbortController | null>(null);
  const preValidateAbortRef = useRef<AbortController | null>(null);
  const fixGenerateAbortRef = useRef<AbortController | null>(null);
  const preValidateMergedRef = useRef<ResumeData | null>(null);
  const copiedTextTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  const resumeIdRef = useRef<string | null>(currentResumeId);
  const { execute: executeAI } = useAIAction({ operation: 'tailor' });
  const queryClient = useQueryClient();
  const redactedResume = useRedactedResume(currentResume as ResumeData | null);

  useEffect(() => {
    activityTracker.setActiveFeature('Smart Tailor');
    return () => {
      activityTracker.setActiveFeature(null);
      if (copiedTextTimerRef.current) clearTimeout(copiedTextTimerRef.current);
    };
  }, []);

  useEffect(() => {
    if (customInstructions) {
      localStorage.setItem(CUSTOM_INSTRUCTIONS_KEY, customInstructions);
    } else {
      localStorage.removeItem(CUSTOM_INSTRUCTIONS_KEY);
    }
  }, [customInstructions]);

  const preloadedJob = searchParams.get('job') || '';
  const preloadedTitle = searchParams.get('title') || '';
  const preloadedCompany = searchParams.get('company') || '';

  useEffect(() => {
    if (preloadedJob && !jobDescription) {
      setJobDescription(preloadedJob);
    }
    if (preloadedTitle && preloadedCompany) {
      setParsedJobInfo({ title: preloadedTitle, company: preloadedCompany });
    }
  }, []); // eslint-disable-line react-hooks/exhaustive-deps

  // Hydrate from Zustand pendingTailor when navigated from TailorSheet
  useEffect(() => {
    if (pendingTailorResult && !tailorResult) {
      setTailorResult(pendingTailorResult);
      if (pendingTailorOriginal) setOriginalResume(pendingTailorOriginal);
      if (pendingTailorJobInfo) setParsedJobInfo(pendingTailorJobInfo);
      if (pendingTailorIntensity) setIntensity(pendingTailorIntensity);
      if (pendingTailorJobUrl) setJobUrl(pendingTailorJobUrl);
      if (pendingTailorSections?.length) {
        setEnabledSections(pendingTailorSections);
      } else {
        setEnabledSections(['summary', 'skills', 'experience', 'education', 'projects', 'certifications', 'awards']);
      }
      setRevealedSections(new Set(['summary', 'skills', 'experience', 'education', 'projects', 'certifications'] as TailorSectionId[]));
    }
  // Only run once on mount — tailorResult starting null triggers hydration
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [pendingTailorResult]);

  useEffect(() => {
    if (!paramResumeId || !allResumes) return;
    if (currentResumeId === paramResumeId) return;
    const found = allResumes.find((r: DatabaseResume) => r.id === paramResumeId);
    if (found) {
      setCurrentResumeId(paramResumeId);
    }
  }, [paramResumeId, allResumes, currentResumeId, setCurrentResumeId]);

  // Auto-select the most recently updated resume when the user lands on
  // /tailor without an explicit resumeId param and nothing is loaded yet.
  // Prevents the page from rendering a "Select a resume" picker that the
  // user has to manually click through every visit when they only have
  // one (or one favourite) resume.
  useEffect(() => {
    if (paramResumeId) return;
    if (currentResume) return;
    if (!allResumes || allResumes.length === 0) return;
    const mostRecent = [...allResumes].sort((a: DatabaseResume, b: DatabaseResume) => {
      const at = new Date(a.updated_at ?? a.created_at ?? 0).getTime();
      const bt = new Date(b.updated_at ?? b.created_at ?? 0).getTime();
      return bt - at;
    })[0];
    if (mostRecent) {
      setCurrentResumeId(mostRecent.id);
    }
  }, [paramResumeId, currentResume, allResumes, setCurrentResumeId]);

  useEffect(() => {
    resumeIdRef.current = currentResumeId;
  }, [currentResumeId]);

  useEffect(() => {
    if (!allResumes) return;
    if (currentResumeId && !allResumes.find((r: DatabaseResume) => r.id === currentResumeId)) {
      setCurrentResumeId(null);
    }
  }, [allResumes, currentResumeId, setCurrentResumeId]);

  const handleResumeSwitch = useCallback((resumeId: string) => {
    if (!allResumes || allResumes.length === 0) return;
    const found = allResumes.find((r: DatabaseResume) => r.id === resumeId);
    if (!found) return;
    if (resumeId === currentResumeId) return;
    fixGenerateAbortRef.current?.abort();
    fixGenerateAbortRef.current = null;
    preValidateAbortRef.current?.abort();
    preValidateAbortRef.current = null;
    preValidateMergedRef.current = null;
    setCurrentResumeId(resumeId);
    setTailorResult(null);
    setOriginalResume(null);
    setTailorError(null);
    setPreValidatorResult(null);
    setIsPreValidating(false);
    setFixSuggestions(null);
    setIsGeneratingFixes(false);
    setAppliedFixes([]);
    setRejectedBullets(new Set());
    setDismissedIssueIndices(new Set());
    setParsedJobInfo(null);
    toast.dismiss();
    toast.success('Resume switched — ready to tailor');
  }, [allResumes, currentResumeId]);

  const toggleSection = (sectionId: TailorSectionId) => {
    setEnabledSections(prev =>
      prev.includes(sectionId) ? prev.filter(s => s !== sectionId) : [...prev, sectionId]
    );
  };

  const resumeText = useMemo(() => {
    if (!currentResume) return '';
    return [
      currentResume.summary,
      ...currentResume.experience.map(e => `${e.position} ${e.company} ${e.description} ${e.achievements.join(' ')}`),
      ...currentResume.education.map(e => `${e.degree} ${e.field} ${e.institution}`),
      ...currentResume.skills,
    ].join(' ');
  }, [currentResume]);

  const hasResumeForFlow = !!currentResume;
  const hasJobForFlow = !!jobDescription.trim();

  useEffect(() => {
    if (isTailoring || tailorResult || showAppliedCTA) {
      setWizardStep('run');
    }
  }, [isTailoring, tailorResult, showAppliedCTA]);

  const handleWizardStepClick = useCallback(
    (step: TailorFlowStep) => {
      if (canAccessTailorStep(step, hasResumeForFlow, hasJobForFlow)) {
        setWizardStep(step);
      }
    },
    [hasResumeForFlow, hasJobForFlow],
  );

  const goWizardBack = useCallback(() => {
    const idx = tailorStepIndex(wizardStep);
    if (idx > 0) setWizardStep(TAILOR_FLOW_STEPS[idx - 1]);
  }, [wizardStep]);

  const goWizardContinue = useCallback(() => {
    const idx = tailorStepIndex(wizardStep);
    if (idx < TAILOR_FLOW_STEPS.length - 1) {
      setWizardStep(TAILOR_FLOW_STEPS[idx + 1]);
    }
  }, [wizardStep]);

  const handleTailor = useCallback(async () => {
    if (!jobDescription.trim()) { toast.error('Please paste a job description first'); return; }
    if (!currentResume) { toast.error('No resume to tailor'); return; }

    logTailorEvent('optimize-clicked', { resumeId: currentResumeId });
    setTailorError(null);
    setIsTailoring(true);
    setOriginalResume(currentResume);
    setProgress({ step: 'analyzing', progress: 5, message: 'Starting...' });
    setShowAppliedCTA(false);
    setAppliedResumeId(null);
    setAppliedResumeTitle(null);
    setAppliedJobInfo(null);
    setPreValidatorResult(null);
    setIsPreValidating(false);
    setDismissedIssueIndices(new Set());
    setFixSuggestions(null);
    setIsGeneratingFixes(false);
    setAppliedFixes([]);
    fixGenerateAbortRef.current?.abort();
    fixGenerateAbortRef.current = null;
    preValidateMergedRef.current = null;

    // Cancel any in-flight pre-validation from a previous tailor run
    preValidateAbortRef.current?.abort();
    preValidateAbortRef.current = null;

    abortRef.current = new AbortController();

    try {
      const result = await executeAI(async () => {
        return await tailorResumeWithProgress(
          (redactedResume ?? currentResume) as ResumeData,
          jobDescription,
          (p) => setProgress(p),
          intensity,
          abortRef.current!.signal,
          customInstructions || undefined
        );
      });

      if (!result) return;

      const superResult = result as SuperTailorResult;
      setTailorResult(superResult);
      setRevealedSections(new Set());

      // Progressive section reveal: sections populate one-by-one after result arrives
      const sectionOrder: TailorSectionId[] = ['summary', 'skills', 'experience', 'education', 'projects', 'certifications'];
      sectionOrder.forEach((sectionId, idx) => {
        setTimeout(() => {
          setRevealedSections(prev => new Set([...prev, sectionId]));
        }, idx * 180);
      });

      const jobInfo = superResult.jobParsed
        ? { title: superResult.jobParsed.title, company: superResult.jobParsed.company }
        : null;
      if (jobInfo) setParsedJobInfo(jobInfo);

      setPendingTailor({
        result: superResult,
        original: currentResume,
        jobInfo,
        sections: enabledSections,
        intensity,
        jobUrl: jobUrl || null,
      });

      // Fire-and-forget pre-validate: runs in background after result arrives
      setIsPreValidating(true);
      (async () => {
        const capturedResumeId = resumeIdRef.current;
        try {
          const mergedForValidation = buildMergedResume(currentResume, superResult, enabledSections, new Set());
          preValidateMergedRef.current = mergedForValidation;
          const thisAbort = new AbortController();
          preValidateAbortRef.current = thisAbort;
          try {
            const { data: vResult, error: vError } = await appwriteFunctions.invoke<ValidatorResult>('validate-tailor', {
              body: {
                originalResume: currentResume,
                jobDescription,
                finalResume: mergedForValidation,
                mustHaveKeywords: superResult.atsAnalysis?.criticalKeywords ?? [],
              },
            });
            // Only apply result if this is still the current pre-validate request and same resume
            if (!vError && vResult && preValidateAbortRef.current === thisAbort) {
              invalidateAiCreditQueries(queryClient);
              if (resumeIdRef.current !== capturedResumeId) return;
              setPreValidatorResult(vResult);
            }
          } finally {
            /* no-op: invoke does not use AbortController */
          }
        } catch {
          // Non-fatal — pre-validation is advisory only
        } finally {
          if (resumeIdRef.current !== capturedResumeId) return;
          setIsPreValidating(false);
        }
      })();
    } catch (error) {
      const err = error as TailorError;
      const rawMsg = err?.message;
      const safeMsg =
        typeof rawMsg === 'string' && rawMsg.length > 0
          ? rawMsg
          : typeof err === 'string'
            ? err
            : 'Failed to tailor resume';
      setTailorError({ message: safeMsg, code: err?.code });
    } finally {
      setIsTailoring(false);
      setProgress(null);
    }
  }, [jobDescription, currentResume, currentResumeId, intensity, customInstructions, executeAI, setPendingTailor, jobUrl, redactedResume, enabledSections]);

  const handleDismissIssue = useCallback((index: number) => {
    setDismissedIssueIndices(prev => new Set([...prev, index]));
  }, []);

  // Fire generate-fix-suggestions whenever pre-validation result arrives
  useEffect(() => {
    if (!preValidatorResult) {
      fixGenerateAbortRef.current?.abort();
      fixGenerateAbortRef.current = null;
      setFixSuggestions(null);
      setIsGeneratingFixes(false);
      return;
    }
    if (preValidatorResult.missing_keywords.length === 0 && preValidatorResult.issues.length === 0) {
      fixGenerateAbortRef.current?.abort();
      fixGenerateAbortRef.current = null;
      setIsGeneratingFixes(false);
      setFixSuggestions([]);
      return;
    }
    fixGenerateAbortRef.current?.abort();
    setIsGeneratingFixes(true);
    setFixSuggestions(null);
    (async () => {
      const thisAbort = new AbortController();
      fixGenerateAbortRef.current = thisAbort;
      const capturedResumeId = resumeIdRef.current;
      if (!preValidateMergedRef.current) {
        if (resumeIdRef.current !== capturedResumeId) return;
        setFixSuggestions([]);
        setIsGeneratingFixes(false);
        return;
      }
      try {
        const { data: fixes, error: fixError } = await appwriteFunctions.invoke<FixSuggestion[]>('generate-fix-suggestions', {
          body: {
            finalResume: preValidateMergedRef.current,
            jobDescription,
            missing_keywords: preValidatorResult.missing_keywords,
            issues: preValidatorResult.issues,
          },
        });
        if (fixGenerateAbortRef.current !== thisAbort) return;
        if (resumeIdRef.current !== capturedResumeId) return;
        if (!fixError && fixes) {
          invalidateAiCreditQueries(queryClient);
          setFixSuggestions(fixes.slice(0, 5));
        } else {
          setFixSuggestions([]);
        }
      } catch {
        if (fixGenerateAbortRef.current === thisAbort && resumeIdRef.current === capturedResumeId) setFixSuggestions([]);
      } finally {
        if (fixGenerateAbortRef.current === thisAbort && resumeIdRef.current === capturedResumeId) setIsGeneratingFixes(false);
      }
    })();
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [preValidatorResult, jobDescription]);

  const handleApplyFix = useCallback((targetFix: FixSuggestion) => {
    setFixSuggestions(prev => {
      if (!prev) return prev;
      const idx = prev.findIndex(f =>
        f.type === targetFix.type &&
        f.after === targetFix.after &&
        f.target_id === targetFix.target_id
      );
      if (idx === -1) return prev;
      setAppliedFixes(current => {
        if (current.length >= MAX_APPLIED_FIXES) return current;
        const exists = current.some(f =>
          f.type === targetFix.type &&
          f.after === targetFix.after &&
          f.target_id === targetFix.target_id
        );
        if (exists) return current;
        return [...current, targetFix];
      });
      return prev.filter((_, i) => i !== idx);
    });
  }, []);

  const handleApplyChanges = useCallback(async () => {
    if (!tailorResult || !currentResume || !user) return;
    if (!currentResumeId) { toast.error('Please select a resume before applying changes.'); return; }

    logTailorEvent('apply-changes-clicked', { resumeId: currentResumeId });
    setIsApplying(true);
    try {
      const mergedResume = applyFixesOnTop(
        buildMergedResume(currentResume, tailorResult, enabledSections, rejectedBullets),
        appliedFixes,
        enabledSections,
      );

      const jobTitle = parsedJobInfo?.title || tailorResult.jobParsed?.title || 'Position';
      const company = parsedJobInfo?.company || tailorResult.jobParsed?.company || 'Company';
      const originalTitle = currentResume.contactInfo.fullName || 'Resume';
      const newTitle = `${originalTitle} - Tailored for ${jobTitle} @ ${company}`;

      // Phase: validate the final merged resume before saving.
      // The validator score is the single source of truth for job_match_score.
      // On timeout or error we fall back to the generator's estimated score.
      let validatorResult: ValidatorResult | null = null;
      try {
        const { data: vResult, error: vError } = await appwriteFunctions.invoke<ValidatorResult>('validate-tailor', {
          body: {
            originalResume: currentResume,
            jobDescription,
            finalResume: mergedResume,
            mustHaveKeywords: tailorResult.atsAnalysis?.criticalKeywords ?? [],
          },
        });
        if (!vError && vResult) {
          invalidateAiCreditQueries(queryClient);
          validatorResult = vResult;
        }
      } catch {
        // Non-fatal: validator error — fall back to generator score
      }

      const finalMatchScore =
        validatorResult !== null
          ? validatorResult.score
          : (tailorResult.overallScore?.after ?? null);

      const newDoc = await databases.createDocument(DATABASE_ID, COLLECTIONS.resumes, ID.unique(), {
        user_id: user.id,
        title: newTitle,
        parent_resume_id: currentResumeId ?? undefined,
        contact_info: JSON.stringify(mergedResume.contactInfo),
        summary: mergedResume.summary,
        experience: JSON.stringify(mergedResume.experience),
        education: JSON.stringify(mergedResume.education),
        skills: JSON.stringify(mergedResume.skills),
        certifications: JSON.stringify(mergedResume.certifications),
        projects: JSON.stringify(mergedResume.projects),
        awards: JSON.stringify(mergedResume.awards),
        template: mergedResume.templateId || 'modern',
      });

      addTailorHistory({
        jobTitle,
        company,
        jobDescription,
        jobUrl: jobUrl || null,
        tailoredResumeId: newDoc.$id,
        tailorResult,
        scoreBeforeAfter: tailorResult.overallScore ?? { before: 0, after: 0 },
        verifiedScore: finalMatchScore,
        appliedSections: enabledSections,
      }, currentResumeId || undefined);

      const matchedCount = validatorResult?.matched_keywords?.length ?? tailorResult.atsAnalysis?.matchedKeywords?.length ?? 0;
      setAppliedResumeId(newDoc.$id);
      setAppliedResumeTitle(newTitle);
      setAppliedJobInfo({ title: jobTitle, company });
      setAppliedScore(tailorResult.overallScore ?? null);
      setAppliedKeywordCount(matchedCount > 0 ? matchedCount : null);
      setAppliedValidatorResult(validatorResult);
      logTailorEvent('success-screen-shown', {
        score: tailorResult.overallScore,
        validatedScore: validatorResult?.score ?? null,
        keywordsMatched: matchedCount,
      });
      setShowAppliedCTA(true);
      setTailorResult(null);

      clearPendingTailor();
    } catch {
      toast.error('Failed to create tailored resume');
    } finally {
      setIsApplying(false);
    }
  }, [tailorResult, currentResume, user, enabledSections, rejectedBullets, appliedFixes, parsedJobInfo, currentResumeId, jobDescription, addTailorHistory, clearPendingTailor, jobUrl, navigate]);

  const handleCopyPlainText = useCallback(async () => {
    if (!currentResume || !tailorResult) return;
    const text = buildPlainText(currentResume, tailorResult, enabledSections);
    try {
      await navigator.clipboard.writeText(text);
      setCopiedText(true);
      toast.success('Copied to clipboard!');
      if (copiedTextTimerRef.current) clearTimeout(copiedTextTimerRef.current);
      copiedTextTimerRef.current = setTimeout(() => setCopiedText(false), 2000);
    } catch {
      toast.error('Failed to copy — try again');
    }
  }, [currentResume, tailorResult, enabledSections]);

  const handleRegenerateSection = useCallback(async (sectionId: TailorSectionId, sectionInstruction?: string) => {
    if (!tailorResult) return;

    const getCurrentContent = (): string | string[] | null => {
      if (sectionId === 'summary') return tailorResult.summary;
      if (sectionId === 'skills') return tailorResult.skills;
      if (sectionId === 'experience') return tailorResult.experience.flatMap(e => e.achievements ?? []);
      if (sectionId === 'education') return tailorResult.education.map(e => e.field || `${e.degree} at ${e.institution}`);
      if (sectionId === 'projects') return (tailorResult.projects ?? []).map(p => p.description || '');
      if (sectionId === 'certifications') return (tailorResult.certifications ?? []).map(c => c.name);
      return null;
    };

    const currentContent = getCurrentContent();
    if (currentContent === null) return;

    const combinedInstructions = [customInstructions, sectionInstruction].filter(s => s?.trim()).join(' | ') || undefined;

    const projectItems = sectionId === 'projects' && tailorResult.projects?.length
      ? tailorResult.projects.map(p => ({ name: p.name, description: p.description || '', technologies: p.technologies, role: p.role }))
      : undefined;

    try {
      const result = await tailorSection({
        section: sectionId,
        currentContent,
        jobDescription,
        jobKeywords: tailorResult.atsAnalysis?.criticalKeywords,
        userInstructions: combinedInstructions,
        intensity,
        projectItems,
      });
      if (sectionId === 'summary' && typeof result.rewrittenContent === 'string') {
        setTailorResult(prev => prev ? { ...prev, summary: result.rewrittenContent as string } : prev);
      } else if (sectionId === 'skills' && Array.isArray(result.rewrittenContent)) {
        setTailorResult(prev => prev ? { ...prev, skills: result.rewrittenContent as string[] } : prev);
      } else if (sectionId === 'experience' && Array.isArray(result.rewrittenContent)) {
        const newBullets = result.rewrittenContent as string[];
        setTailorResult(prev => {
          if (!prev) return prev;
          let bulletIdx = 0;
          const updatedExperience = prev.experience.map(exp => {
            const count = (exp.achievements ?? []).length;
            const slice = newBullets.slice(bulletIdx, bulletIdx + count);
            bulletIdx += count;
            return { ...exp, achievements: slice.length > 0 ? slice : exp.achievements };
          });
          return { ...prev, experience: updatedExperience, bulletTransformations: [] };
        });
      } else if (sectionId === 'education' && Array.isArray(result.rewrittenContent)) {
        const newFields = result.rewrittenContent as string[];
        setTailorResult(prev => {
          if (!prev) return prev;
          const updatedEducation = prev.education.map((edu, i) => ({
            ...edu,
            field: newFields[i] ?? edu.field,
          }));
          return { ...prev, education: updatedEducation };
        });
      } else if (sectionId === 'projects' && Array.isArray(result.rewrittenContent)) {
        const newDescriptions = result.rewrittenContent as string[];
        setTailorResult(prev => {
          if (!prev) return prev;
          const updatedProjects = (prev.projects ?? []).map((p, i) => ({
            ...p,
            description: (newDescriptions[i] ?? '').trim() || p.description,
          }));
          return { ...prev, projects: updatedProjects };
        });
      } else if (sectionId === 'certifications' && Array.isArray(result.rewrittenContent)) {
        const newNames = result.rewrittenContent as string[];
        setTailorResult(prev => {
          if (!prev) return prev;
          const updatedCertifications = (prev.certifications ?? []).map((c, i) => ({
            ...c,
            name: newNames[i] ?? c.name,
          }));
          return { ...prev, certifications: updatedCertifications };
        });
      }
      toast.success(`${sectionId.charAt(0).toUpperCase() + sectionId.slice(1)} section regenerated`);
    } catch (err) {
      const error = err as Error;
      toast.error(error.message || 'Failed to regenerate section');
    }
  }, [tailorResult, jobDescription, customInstructions, intensity]);

  const handleTrackApplication = useCallback(() => {
    const jobTitle = appliedJobInfo?.title || parsedJobInfo?.title || tailorResult?.jobParsed?.title || '';
    const company = appliedJobInfo?.company || parsedJobInfo?.company || tailorResult?.jobParsed?.company || '';
    const params = new URLSearchParams();
    params.set('new', '1');
    if (jobTitle) params.set('title', jobTitle);
    if (company) params.set('company', company);
    if (appliedResumeId) params.set('resumeId', appliedResumeId);
    navigate(`/applications?${params.toString()}`);
  }, [navigate, parsedJobInfo, tailorResult, appliedResumeId, appliedJobInfo]);

  const handleViewResume = useCallback(() => {
    if (appliedResumeId) navigate(`/editor?id=${appliedResumeId}`);
  }, [navigate, appliedResumeId]);

  const handleCloseSuccess = useCallback(() => {
    setShowAppliedCTA(false);
    setAppliedResumeId(null);
    setAppliedResumeTitle(null);
    setAppliedJobInfo(null);
    setAppliedScore(null);
    setAppliedKeywordCount(null);
    setAppliedValidatorResult(null);
    navigate(-1);
  }, [navigate]);

  const handleGoToPortfolio = useCallback(() => {
    logTailorEvent('portfolio-cta-clicked', { resumeId: appliedResumeId });
    navigate('/portfolio');
  }, [navigate, appliedResumeId]);

  const showResultsPanel = isTailoring || !!tailorResult || !!tailorError || showAppliedCTA;

  const resultsPanelProps = {
    isTailoring,
    progress,
    tailorResult,
    tailorError,
    originalResume,
    enabledSections,
    toggleSection,
    onApplyChanges: handleApplyChanges,
    onPreview: () => setShowTailorPreview(true),
    isApplying,
    onRetry: () => { setTailorError(null); handleTailor(); },
    onSettings: () => {},
    onRevert: () => { setTailorResult(null); setAppliedFixes([]); },
    abortRef,
    setIsTailoring,
    setProgress,
    showAppliedCTA,
    appliedResumeId,
    appliedResumeTitle,
    appliedJobInfo,
    onViewResume: handleViewResume,
    onTrackApplication: handleTrackApplication,
    onCloseSuccess: handleCloseSuccess,
    onGoToPortfolio: handleGoToPortfolio,
    appliedScore,
    appliedKeywordCount,
    appliedValidatorResult,
    copiedText,
    onCopyText: handleCopyPlainText,
    onReTailor: handleTailor,
    rejectedBullets,
    onBulletReject: setRejectedBullets,
    onRegenerate: handleRegenerateSection,
    revealedSections,
    preValidatorResult,
    isPreValidating,
    dismissedIssueIndices,
    onDismissIssue: handleDismissIssue,
    fixSuggestions,
    isGeneratingFixes,
    appliedFixes,
    onApplyFix: handleApplyFix,
  };

  return (
    <div className="tailor-workspace flex-1 flex flex-col min-h-0 h-full overflow-hidden">
      <TailorPageHeader
        onBack={() => navigate(getBackRoute('/tailor'))}
        copyAction={
          tailorResult
            ? { copied: copiedText, onCopy: handleCopyPlainText }
            : undefined
        }
      />

      <div className="tailor-workspace-body">
        <div className="tailor-setup-panel">
          <div className="tailor-setup-panel__rail">
            <TailorStepRail
              variant="vertical"
              activeStep={wizardStep}
              hasResume={hasResumeForFlow}
              hasJob={hasJobForFlow}
              onStepClick={handleWizardStepClick}
            />
          </div>
          <div className="tailor-setup-panel__scroll tailor-setup-wizard">
            <div className="tailor-wizard-stage">
              {wizardStep === 'resume' && (
                <TailorStepCard
                  step={1}
                  title="Choose your resume"
                  subtitle="We'll optimize this version for the role you're targeting."
                  active
                >
                  {allResumes === undefined ? (
                    <div className="animate-pulse h-9 rounded-lg bg-muted w-full" />
                  ) : allResumes.length === 0 ? (
                    <div className="space-y-3">
                      <p className="text-sm text-muted-foreground">
                        You don't have a resume yet. Upload your existing CV (PDF or DOCX) and
                        we'll tailor it for this job in seconds.
                      </p>
                      <Button
                        className="w-full"
                        onClick={() => navigate('/upload?next=/tailor')}
                      >
                        <Wand2 className="w-4 h-4 mr-2" />
                        Upload your resume
                      </Button>
                    </div>
                  ) : (
                    <Select
                      value={allResumes.some(r => r.id === currentResumeId) ? (currentResumeId ?? undefined) : undefined}
                      onValueChange={handleResumeSwitch}
                      disabled={isTailoring || isApplying}
                    >
                      <SelectTrigger className="tailor-resume-select w-full">
                        <SelectValue placeholder="Select a resume">
                          {selectedResumeTitle || undefined}
                        </SelectValue>
                      </SelectTrigger>
                      <SelectContent>
                        {allResumes.map((r: DatabaseResume, index: number) => (
                          <SelectItem key={`${r.id}-${index}`} value={r.id}>
                            {r.title}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                  )}
                </TailorStepCard>
              )}

              {wizardStep === 'job' && (
                <TailorStepCard
                  step={2}
                  title="Target job"
                  subtitle="Paste the posting or import from a job URL — we'll extract the essentials."
                  active
                >
                  <div className="tailor-job-shell">
                    <JobUrlParser
                      value={jobDescription}
                      onChange={setJobDescription}
                      onParsed={(info) => {
                        setParsedJobInfo(info);
                        if (info?.url) setJobUrl(info.url);
                      }}
                    />
                  </div>
                  {hasJobForFlow && hasResumeForFlow && (
                    <div className="tailor-keyword-panel mt-3">
                      <KeywordMatchBar jobDescription={jobDescription} resumeText={resumeText} />
                    </div>
                  )}
                </TailorStepCard>
              )}

              {wizardStep === 'options' && (
                <TailorStepCard
                  step={3}
                  title="Fine-tune (optional)"
                  subtitle="Add context for seniority, tone, or emphasis before running the optimizer."
                  active
                >
                  <button
                    type="button"
                    onClick={() => setShowCustomInstructions(v => !v)}
                    className="flex items-center gap-2 text-sm text-muted-foreground hover:text-foreground transition-colors w-full rounded-xl border border-border/60 px-3 py-2.5 bg-muted/20"
                  >
                    {showCustomInstructions ? <ChevronUp className="w-3.5 h-3.5" /> : <ChevronDown className="w-3.5 h-3.5" />}
                    Custom instructions
                    {customInstructions && <Badge variant="outline" className="text-[10px] px-1.5 py-0 ml-auto">saved</Badge>}
                  </button>
                  {showCustomInstructions && (
                    <div className="space-y-2 pt-1">
                      <Textarea
                        value={customInstructions}
                        onChange={e => setCustomInstructions(e.target.value)}
                        placeholder="e.g. I'm applying as a senior candidate, emphasize leadership..."
                        className="min-h-[88px] resize-none text-sm rounded-xl border-border/80"
                        maxLength={2000}
                      />
                      <p className="text-xs text-muted-foreground text-right">{customInstructions.length}/2000</p>
                    </div>
                  )}
                </TailorStepCard>
              )}

              {wizardStep === 'run' && (
                <TailorStepCard
                  step={4}
                  title="Tailoring intensity"
                  subtitle="Control how aggressively we rewrite content to match the role."
                  active
                >
                  <ToggleGroup
                    type="single"
                    value={intensity}
                    onValueChange={(val) => val && setIntensity(val as TailorIntensity)}
                    className="tailor-intensity-grid w-full grid grid-cols-3 gap-2"
                  >
                    <ToggleGroupItem
                      value="light"
                      className="tailor-intensity-option text-xs gap-1 min-h-[48px] rounded-xl border border-border/80 data-[state=on]:bg-primary data-[state=on]:text-primary-foreground"
                    >
                      <Zap className="w-3.5 h-3.5" /> Light
                    </ToggleGroupItem>
                    <ToggleGroupItem
                      value="moderate"
                      className="tailor-intensity-option text-xs gap-1 min-h-[48px] rounded-xl border border-border/80 data-[state=on]:bg-primary data-[state=on]:text-primary-foreground"
                    >
                      <Gauge className="w-3.5 h-3.5" /> Moderate
                    </ToggleGroupItem>
                    <ToggleGroupItem
                      value="aggressive"
                      className="tailor-intensity-option text-xs gap-1 min-h-[48px] rounded-xl border border-border/80 data-[state=on]:bg-primary data-[state=on]:text-primary-foreground"
                    >
                      <Flame className="w-3.5 h-3.5" /> Aggressive
                    </ToggleGroupItem>
                  </ToggleGroup>
                  <p className="text-xs text-muted-foreground leading-relaxed px-0.5">
                    {intensity === 'light' && 'Light touch — keyword alignment with minimal rewrites.'}
                    {intensity === 'moderate' && 'Balanced — stronger phrasing and ATS keyword coverage.'}
                    {intensity === 'aggressive' && 'Maximum match — bold rewrites for competitive roles.'}
                  </p>
                  <div className="space-y-2 pt-2">
                    <Button
                      className="tailor-cta-primary w-full h-12 min-h-[48px] font-semibold text-primary-foreground rounded-xl"
                      onClick={handleTailor}
                      disabled={isTailoring || !hasJobForFlow || !hasResumeForFlow}
                    >
                      {isTailoring ? (
                        <><MiniSpinner size={20} className="mr-2" />Optimizing…</>
                      ) : (
                        <><Wand2 className="w-5 h-5 mr-2" />Run optimizer</>
                      )}
                    </Button>
                    {!isTailoring && (
                      <p className="tailor-cta-hint">
                        Typical run time 10–20 seconds · Results appear in the studio panel →
                      </p>
                    )}
                  </div>
                </TailorStepCard>
              )}
            </div>

            {wizardStep !== 'run' && (
              <TailorSetupWizardFooter
                step={wizardStep}
                canContinue={canContinueTailorStep(wizardStep, hasResumeForFlow, hasJobForFlow)}
                onBack={goWizardBack}
                onContinue={goWizardContinue}
              />
            )}

            {wizardStep === 'run' && (
              <div className="tailor-wizard-footer tailor-wizard-footer--run-only">
                <Button
                  type="button"
                  variant="outline"
                  className="w-full min-h-[44px] rounded-xl"
                  onClick={goWizardBack}
                  disabled={isTailoring}
                >
                  Back
                </Button>
              </div>
            )}

          {wizardStep === 'run' && (
          <div className="lg:hidden space-y-4 pt-2">
            {showResultsPanel ? (
              <div className="tailor-results-panel">
                <ResultsPanel {...resultsPanelProps} />
              </div>
            ) : (
              <TailorDemoPanel />
            )}
          </div>
          )}
          </div>
        </div>

        <TailorResultsStage hasContent={showResultsPanel} className="hidden lg:flex">
          {showResultsPanel ? (
            <div className="tailor-results-panel">
              <ResultsPanel {...resultsPanelProps} />
            </div>
          ) : (
            <TailorDemoPanel />
          )}
        </TailorResultsStage>
      </div>


      {/* Tailored Resume Preview Sheet — ephemeral render of merged result */}
      <TailorPreviewSheet
        open={showTailorPreview}
        onOpenChange={setShowTailorPreview}
        resume={
          tailorResult && currentResume
            ? applyFixesOnTop(
                buildMergedResume(currentResume, tailorResult, enabledSections, rejectedBullets),
                appliedFixes,
                enabledSections,
              )
            : null
        }
        onApply={() => {
          setShowTailorPreview(false);
          handleApplyChanges();
        }}
        isApplying={isApplying}
        applyLabel={preValidatorResult ? `Apply (${preValidatorResult.score}% → Verified)` : `Apply (${enabledSections.length})`}
        jobTitle={parsedJobInfo?.title || tailorResult?.jobParsed?.title}
      />
    </div>
  );
}

function SectionRevealWrapper({ revealed, title, children }: { revealed: boolean; title: string; children: ReactNode }) {
  if (revealed) return <>{children}</>;
  return (
    <div className="rounded-xl border-2 border-l-4 border-primary/20 border-l-primary/40 bg-primary/5 p-4 animate-pulse">
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2">
          <MiniSpinner size={16} className="text-primary/60" />
          <span className="text-sm font-medium text-muted-foreground">{title}</span>
        </div>
        <div className="h-5 rounded w-12 bg-primary/20" />
      </div>
      <div className="mt-3 space-y-1.5">
        <div className="h-2 rounded bg-muted w-full" />
        <div className="h-2 rounded bg-muted w-4/5" />
      </div>
    </div>
  );
}

interface ResultsPanelProps {
  isTailoring: boolean;
  progress: TailorProgress | EnhancedTailorProgress | null;
  rejectedBullets: Set<string>;
  onBulletReject: (keys: Set<string>) => void;
  tailorResult: SuperTailorResult | null;
  tailorError: { message: string; code?: string } | null;
  originalResume: ResumeData | null;
  enabledSections: TailorSectionId[];
  toggleSection: (s: TailorSectionId) => void;
  onApplyChanges: () => void;
  onPreview: () => void;
  isApplying: boolean;
  onRetry: () => void;
  onSettings: () => void;
  onRevert: () => void;
  abortRef: ReturnType<typeof useRef<AbortController | null>>;
  setIsTailoring: (v: boolean) => void;
  setProgress: (v: TailorProgress | EnhancedTailorProgress | null) => void;
  showAppliedCTA: boolean;
  appliedResumeId: string | null;
  appliedResumeTitle: string | null;
  appliedJobInfo: { title: string; company: string } | null;
  onViewResume: () => void;
  onTrackApplication: () => void;
  onCloseSuccess: () => void;
  onGoToPortfolio: () => void;
  appliedScore: { before: number; after: number } | null;
  appliedKeywordCount: number | null;
  appliedValidatorResult: ValidatorResult | null;
  copiedText: boolean;
  onCopyText: () => void;
  onReTailor: () => void;
  onRegenerate: (sectionId: TailorSectionId, instruction?: string) => Promise<void>;
  revealedSections: Set<TailorSectionId>;
  preValidatorResult: ValidatorResult | null;
  isPreValidating: boolean;
  dismissedIssueIndices: Set<number>;
  onDismissIssue: (index: number) => void;
  fixSuggestions: FixSuggestion[] | null;
  isGeneratingFixes: boolean;
  appliedFixes: FixSuggestion[];
  onApplyFix: (fix: FixSuggestion) => void;
}

function ScoreLabel({ score }: { score: number }) {
  const color = score >= 85 ? 'text-success' : score >= 70 ? 'text-warning' : 'text-destructive';
  return <span className={cn('text-2xl font-bold tabular-nums', color)}>{score}%</span>;
}

/** Maps each issue index to the most relevant section (or 'global' for catch-all). */
function mapIssuesToSections(issues: string[]): Map<TailorSectionId | 'global', number[]> {
  const priorityMap: Array<{ sectionId: TailorSectionId | 'global'; keywords: string[] }> = [
    { sectionId: 'summary', keywords: ['summary', 'objective'] },
    { sectionId: 'education', keywords: ['education', 'degree', 'university', 'college', 'gpa', 'coursework'] },
    { sectionId: 'projects', keywords: ['project'] },
    { sectionId: 'certifications', keywords: ['certification', 'certificate', 'credential', 'licensed'] },
    // awards intentionally omitted — no callout render path in ResultsPanel; falls to 'global'
    { sectionId: 'skills', keywords: ['skill', 'technology', 'tool', 'hallucinated', 'fabricated', 'invented'] },
    { sectionId: 'experience', keywords: ['bullet', 'achievement', 'experience', 'position', 'responsible for', 'generic phrasing', 'vague', 'weak phrasing'] },
  ];

  const result = new Map<TailorSectionId | 'global', number[]>();
  issues.forEach((issue, i) => {
    const lower = issue.toLowerCase();
    let assigned = false;
    for (const { sectionId, keywords } of priorityMap) {
      if (keywords.some(kw => lower.includes(kw))) {
        if (!result.has(sectionId)) result.set(sectionId, []);
        result.get(sectionId)!.push(i);
        assigned = true;
        break;
      }
    }
    if (!assigned) {
      if (!result.has('global')) result.set('global', []);
      result.get('global')!.push(i);
    }
  });
  return result;
}

interface SectionIssueCalloutsProps {
  sectionId: TailorSectionId;
  issueIndices: number[];
  issues: string[];
  dismissedIssueIndices: Set<number>;
  onDismissIssue: (index: number) => void;
}

function FixSuggestionCard({ fix, onApply }: { fix: FixSuggestion; onApply: () => void }) {
  const typeLabel =
    fix.type === 'add_skill'
      ? 'Add skill'
      : fix.type === 'improve_bullet'
        ? 'Improve bullet'
        : 'Enhance summary';

  return (
    <div className="rounded-lg border border-primary/20 bg-primary/5 p-3 space-y-2">
      <div className="flex items-start justify-between gap-2">
        <span className="text-[10px] font-semibold uppercase tracking-wide text-primary/70">
          {typeLabel}
        </span>
        <Button
          size="sm"
          variant="outline"
          className="h-6 px-2 text-[10px] shrink-0 border-primary/30 text-primary hover:bg-primary/10"
          onClick={onApply}
        >
          <CheckCircle className="w-3 h-3 mr-1" />
          Apply
        </Button>
      </div>
      {fix.before && (
        <p className="text-xs text-muted-foreground line-through leading-snug">{fix.before}</p>
      )}
      <p className="text-xs font-medium leading-snug line-clamp-6">{fix.after}</p>
      <p className="text-[11px] text-muted-foreground leading-snug">{fix.reason}</p>
    </div>
  );
}

function SectionIssueCallouts({ sectionId: _sectionId, issueIndices, issues, dismissedIssueIndices, onDismissIssue }: SectionIssueCalloutsProps) {
  const visible = issueIndices.filter(i => !dismissedIssueIndices.has(i));
  if (visible.length === 0) return null;
  return (
    <div className="space-y-1.5 -mt-1">
      {visible.map(i => (
        <div key={i} className="flex items-start gap-2 px-3 py-2 rounded-lg bg-warning/10 border border-warning/25">
          <AlertTriangle className="w-3.5 h-3.5 text-warning shrink-0 mt-0.5" />
          <p className="text-xs text-foreground flex-1 leading-snug">{issues[i]}</p>
          <button
            onClick={() => onDismissIssue(i)}
            className="shrink-0 text-muted-foreground hover:text-foreground transition-colors"
            aria-label="Dismiss"
          >
            <X className="w-3.5 h-3.5" />
          </button>
        </div>
      ))}
    </div>
  );
}

function ResultsPanel({
  isTailoring, progress, tailorResult, tailorError, originalResume,
  enabledSections, toggleSection, onApplyChanges, onPreview, isApplying,
  onRetry, onSettings, onRevert, abortRef, setIsTailoring, setProgress,
  showAppliedCTA, appliedResumeId, appliedResumeTitle, appliedJobInfo,
  onViewResume, onTrackApplication, onCloseSuccess, onGoToPortfolio, appliedScore,
  appliedKeywordCount, appliedValidatorResult,
  copiedText, onCopyText, onReTailor,
  rejectedBullets, onBulletReject, onRegenerate, revealedSections,
  preValidatorResult, isPreValidating, dismissedIssueIndices, onDismissIssue,
  fixSuggestions, isGeneratingFixes, appliedFixes, onApplyFix,
}: ResultsPanelProps) {
  const issueMap = useMemo(
    () => preValidatorResult ? mapIssuesToSections(preValidatorResult.issues) : new Map<TailorSectionId | 'global', number[]>(),
    [preValidatorResult]
  );

  const [discardConfirm, setDiscardConfirm] = useState(false);
  const discardTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  useEffect(() => () => { if (discardTimerRef.current) clearTimeout(discardTimerRef.current); }, []);
  const handleDiscardClick = useCallback(() => {
    if (discardConfirm) {
      if (discardTimerRef.current) clearTimeout(discardTimerRef.current);
      setDiscardConfirm(false);
      onRevert();
    } else {
      if (discardTimerRef.current) clearTimeout(discardTimerRef.current);
      setDiscardConfirm(true);
      discardTimerRef.current = setTimeout(() => setDiscardConfirm(false), 3000);
    }
  }, [discardConfirm, onRevert]);

  const sectionDelta = useMemo<Record<'summary' | 'skills' | 'experience' | 'education', number>>(() => {
    if (!tailorResult?.sectionScores) return { summary: 0, skills: 0, experience: 0, education: 0 };
    const scores = tailorResult.sectionScores as unknown as Record<string, { before: number; after: number }>;
    return {
      summary: scores.summary ? scores.summary.after - scores.summary.before : 0,
      skills: scores.skills ? scores.skills.after - scores.skills.before : 0,
      experience: scores.experience ? scores.experience.after - scores.experience.before : 0,
      education: scores.education ? scores.education.after - scores.education.before : 0,
    };
  }, [tailorResult?.sectionScores]);

  const sortedCoreSections = useMemo(
    () =>
      (['summary', 'skills', 'experience', 'education'] as const)
        .slice()
        .sort((a, b) => sectionDelta[b] - sectionDelta[a]),
    [sectionDelta]
  );

  const topSectionId: 'summary' | 'skills' | 'experience' | 'education' = sortedCoreSections[0];

  const skillsChangesSummary = useMemo(() => {
    if (!tailorResult?.skills) return '0 skills optimized';
    if (!originalResume?.skills) return `${tailorResult.skills.length} skills optimized`;
    const diff = compareSkills(originalResume.skills, tailorResult.skills);
    return `Added ${diff.added.length} · Removed ${diff.removed.length} · Kept ${diff.unchanged.length}`;
  }, [originalResume?.skills, tailorResult?.skills]);

  const experienceChangesSummary = useMemo(() => {
    const bts = tailorResult?.bulletTransformations;
    if (!bts || bts.length === 0) return `${tailorResult?.experience?.length ?? 0} positions enhanced`;
    const uniqueCount = new Set(bts.map(bt => bt.experienceId)).size;
    return `${bts.length} bullet${bts.length !== 1 ? 's' : ''} optimized across ${uniqueCount} position${uniqueCount !== 1 ? 's' : ''}`;
  }, [tailorResult?.bulletTransformations, tailorResult?.experience?.length]);

  const summaryChangesSummary = useMemo(() => {
    if (!originalResume?.summary || !tailorResult?.summary) return 'Professional summary rewritten';
    const diffs = diffText(originalResume.summary, tailorResult.summary);
    const wordCount = diffs
      .filter(d => d.type !== 'unchanged')
      .reduce((acc, d) => acc + d.text.split(/\s+/).filter(Boolean).length, 0);
    if (wordCount === 0) return 'Professional summary rewritten';
    return `~${wordCount} word${wordCount !== 1 ? 's' : ''} changed`;
  }, [originalResume?.summary, tailorResult?.summary]);

  if (showAppliedCTA && !isTailoring && !tailorResult) {
    const validatedAfterScore = appliedValidatorResult?.score ?? appliedScore?.after ?? 0;
    const improvement = appliedScore ? validatedAfterScore - appliedScore.before : 0;
    const isVerified = appliedValidatorResult !== null;
    return (
      <div className="tailor-results-panel flex flex-col items-center justify-center gap-6 py-12 px-6 text-center animate-fade-in">
        <div className="w-16 h-16 rounded-full bg-success/10 flex items-center justify-center">
          <CheckCircle className="w-8 h-8 text-success" />
        </div>
        <div className="space-y-2">
          <h3 className="font-bold text-xl">Your resume is now stronger for this job</h3>
          {appliedResumeTitle && (
            <p className="text-sm font-medium text-foreground break-words px-2">
              {appliedResumeTitle}
            </p>
          )}
          {appliedJobInfo && (
            <p className="text-muted-foreground text-xs">
              Tailored for {appliedJobInfo.title} at {appliedJobInfo.company}
            </p>
          )}
        </div>

        {appliedScore && (
          <div className="w-full max-w-xs rounded-2xl bg-card border border-border shadow-soft px-5 py-4">
            <p className="text-xs font-medium text-muted-foreground mb-3 flex items-center justify-center gap-1.5">
              <TrendingUp className="w-3.5 h-3.5" />
              Match Score
            </p>
            <div className="flex items-center justify-center gap-4">
              <div className="text-center">
                <span className="text-2xl font-bold tabular-nums text-muted-foreground">{appliedScore.before}%</span>
                <p className="text-[10px] text-muted-foreground mt-0.5">Before</p>
              </div>
              <span className="text-muted-foreground text-lg">→</span>
              <div className="text-center">
                <ScoreLabel score={validatedAfterScore} />
                <p className="text-[10px] text-muted-foreground mt-0.5">After</p>
              </div>
            </div>
            <div className="mt-3 flex items-center justify-center gap-2 flex-wrap">
              {improvement > 0 ? (
                <span className="inline-flex items-center gap-1 text-xs font-semibold text-success bg-success/10 px-2.5 py-0.5 rounded-full">
                  +{improvement} improvement
                </span>
              ) : (
                <span className="text-xs text-muted-foreground">Your resume has been refined and aligned with this role</span>
              )}
              <span className={cn(
                'inline-flex items-center gap-1 text-xs font-medium px-2 py-0.5 rounded-full',
                isVerified
                  ? 'bg-success/10 text-success'
                  : 'bg-muted text-muted-foreground'
              )}>
                {isVerified ? '✓ Verified' : '~ Estimated'}
              </span>
            </div>
            {appliedValidatorResult?.verdict && (
              <div className="mt-2 flex justify-center">
                <span className={cn(
                  'text-xs font-medium px-2.5 py-0.5 rounded-full',
                  appliedValidatorResult.verdict === 'strong'
                    ? 'bg-success/10 text-success'
                    : appliedValidatorResult.verdict === 'average'
                      ? 'bg-warning/10 text-warning'
                      : 'bg-destructive/10 text-destructive'
                )}>
                  {appliedValidatorResult.verdict === 'strong'
                    ? 'Strong match'
                    : appliedValidatorResult.verdict === 'average'
                      ? 'Average match'
                      : 'Weak match'}
                </span>
              </div>
            )}
            {appliedKeywordCount !== null && appliedKeywordCount > 0 && (
              <p className="text-xs text-muted-foreground mt-2">
                +{appliedKeywordCount} keywords matched
              </p>
            )}
            {appliedValidatorResult?.missing_keywords && appliedValidatorResult.missing_keywords.length > 0 && (
              <div className="mt-2 text-left">
                <p className="text-[10px] font-medium text-muted-foreground mb-1">Still missing:</p>
                <div className="flex flex-wrap gap-1">
                  {appliedValidatorResult.missing_keywords.slice(0, 5).map((kw, i) => (
                    <span key={i} className="text-[10px] bg-destructive/10 text-destructive px-1.5 py-0.5 rounded">{kw}</span>
                  ))}
                  {appliedValidatorResult.missing_keywords.length > 5 && (
                    <span className="text-[10px] text-muted-foreground">+{appliedValidatorResult.missing_keywords.length - 5} more</span>
                  )}
                </div>
              </div>
            )}
            {appliedValidatorResult?.issues && appliedValidatorResult.issues.length > 0 && (
              <details className="mt-2 text-left">
                <summary className="text-[10px] font-medium text-muted-foreground cursor-pointer hover:text-foreground">
                  Review notes ({appliedValidatorResult.issues.length})
                </summary>
                <ul className="mt-1 space-y-0.5">
                  {appliedValidatorResult.issues.map((issue, i) => (
                    <li key={i} className="text-[10px] text-muted-foreground">• {issue}</li>
                  ))}
                </ul>
              </details>
            )}
          </div>
        )}

        <div className="flex flex-col gap-3 w-full max-w-xs">
          {appliedResumeId && (
            <Button className="min-h-[48px] font-semibold shadow-soft-sm" onClick={onViewResume}>
              <ExternalLink className="w-4 h-4 mr-2" />
              View Resume
            </Button>
          )}
          <Button variant="outline" className="min-h-[44px]" onClick={onTrackApplication}>
            <Briefcase className="w-4 h-4 mr-2" />
            Track Application
          </Button>
          <Button variant="outline" className="min-h-[44px]" onClick={onGoToPortfolio}>
            <Globe className="w-4 h-4 mr-2" />
            Turn this into a portfolio
          </Button>
          <Button variant="ghost" className="min-h-[44px]" onClick={onCloseSuccess}>
            Close
          </Button>
        </div>
      </div>
    );
  }
  return (
    <div className="tailor-results-panel space-y-4">
      {isTailoring && progress && (
        <TailorProgressComponent
          progress={progress}
          onCancel={() => {
            abortRef.current?.abort();
            setIsTailoring(false);
            setProgress(null);
            toast.info('Generation cancelled');
          }}
        />
      )}

      {isTailoring && progress && (() => {
        const pct = 'progress' in progress ? (progress as EnhancedTailorProgress).progress : 0;
        const step = 'step' in progress ? (progress as EnhancedTailorProgress).step : '';
        const sectionsReady: Record<string, boolean> = {
          summary: pct >= 35 || step === 'rewriting_summary' || step === 'optimizing_skills' || step === 'transforming_bullets' || step === 'calculating_ats' || step === 'finalizing',
          skills: pct >= 50 || step === 'optimizing_skills' || step === 'transforming_bullets' || step === 'calculating_ats' || step === 'finalizing',
          experience: pct >= 60 || step === 'transforming_bullets' || step === 'calculating_ats' || step === 'finalizing',
          education: pct >= 70 || step === 'calculating_ats' || step === 'finalizing',
        };
        return (
          <div className="space-y-3 animate-pulse">
            <h4 className="font-semibold text-sm flex items-center gap-2">
              <CheckCircle className="w-4 h-4 text-muted-foreground" />
              <span className="text-muted-foreground">Preparing changes...</span>
            </h4>
            {(['summary', 'skills', 'experience', 'education'] as TailorSectionId[]).map(s => (
              <div key={s} className={cn('rounded-xl border-2 border-l-4 p-4 transition-all',
                sectionsReady[s] ? 'border-primary/30 border-l-primary bg-primary/5' : 'border-border border-l-muted-foreground/20 bg-muted/30'
              )}>
                <div className="flex items-center justify-between gap-2">
                  <div className="flex items-center gap-2">
                    <div className={cn('w-4 h-4 rounded', sectionsReady[s] ? 'bg-primary/30' : 'bg-muted-foreground/20')} />
                    <div className={cn('h-3 rounded w-24', sectionsReady[s] ? 'bg-primary/30' : 'bg-muted-foreground/20')} />
                    {sectionsReady[s] && <MiniSpinner size={12} className="text-primary" />}
                  </div>
                  <div className={cn('h-5 rounded w-12', sectionsReady[s] ? 'bg-primary/20' : 'bg-muted-foreground/10')} />
                </div>
                {sectionsReady[s] && (
                  <div className="mt-3 space-y-1.5">
                    <div className="h-2 rounded bg-muted w-full" />
                    <div className="h-2 rounded bg-muted w-5/6" />
                  </div>
                )}
              </div>
            ))}
          </div>
        );
      })()}

      {tailorError && !isTailoring && (
        <div className="p-5 rounded-2xl bg-warning/10 border border-warning/30 shadow-soft-sm space-y-4">
          <div className="flex items-start gap-3">
            <HeartHandshake className="w-5 h-5 text-warning shrink-0 mt-0.5" />
            <div>
              <h4 className="font-semibold text-sm">Something went wrong</h4>
              <p className="text-sm text-muted-foreground mt-1">{tailorError.message}</p>
            </div>
          </div>
          <div className="flex flex-wrap gap-2">
            <Button size="sm" onClick={onRetry} className="min-h-[44px]">
              <RefreshCw className="w-4 h-4 mr-1.5" /> Try Again
            </Button>
            <Button size="sm" variant="outline" onClick={onSettings} className="min-h-[44px]">
              <Key className="w-4 h-4 mr-1.5" /> Use Your Key
            </Button>
            <Button size="sm" variant="ghost" onClick={() => reportBug(new Error(tailorError.message), 'Tailor failed')} className="min-h-[44px] text-muted-foreground">
              <Bug className="w-4 h-4 mr-1.5" /> Report
            </Button>
          </div>
        </div>
      )}

      {tailorResult && !isTailoring && (
        <div className="space-y-4">
          <div className="p-4 sm:p-5 rounded-2xl bg-success/10 border border-success/30 shadow-soft overflow-hidden">
            <div className="flex items-center justify-between mb-2">
              <div className="flex items-center gap-2">
                <Sparkles className="w-5 h-5 text-success" />
                <h4 className="font-semibold">Resume Tailored!</h4>
              </div>
              <div className="flex items-center gap-2">
                <Button size="sm" variant="ghost" onClick={onCopyText} className="text-xs gap-1.5">
                  {copiedText ? <Check className="w-3.5 h-3.5 text-success" /> : <Copy className="w-3.5 h-3.5" />}
                  {copiedText ? 'Copied!' : 'Copy text'}
                </Button>
                <Button size="sm" variant="ghost" onClick={onReTailor} className="text-xs gap-1.5">
                  <RefreshCw className="w-3.5 h-3.5" /> Re-tailor
                </Button>
              </div>
            </div>
            <p className="text-sm text-muted-foreground">
              Review changes below. A new tailored copy will be created — your original stays safe.
            </p>
          </div>

          {/* Score */}
          {tailorResult.overallScore && tailorResult.sectionScores && (
            <ScoreComparison
              beforeScore={tailorResult.overallScore.before}
              afterScore={tailorResult.overallScore.after}
              sectionScores={tailorResult.sectionScores}
              selectedSections={enabledSections}
            />
          )}

          {/* Confidence indicators — static trust signals */}
          <div className="flex flex-col gap-1.5 px-1">
            {[
              { icon: <Check className="w-3.5 h-3.5 text-success shrink-0" />, label: 'Keywords matched from job description' },
              { icon: <Shield className="w-3.5 h-3.5 text-primary shrink-0" />, label: 'ATS-friendly improvements applied' },
              { icon: <TrendingUp className="w-3.5 h-3.5 text-warning shrink-0" />, label: 'Bullet points optimized for impact' },
            ].map(({ icon, label }) => (
              <div key={label} className="flex items-center gap-2 text-xs text-muted-foreground">
                {icon}
                <span>{label}</span>
              </div>
            ))}
          </div>

          {/* Section changes — sorted by impact delta */}
          <div className="space-y-3">
            <h4 className="font-semibold text-sm flex items-center gap-2">
              <CheckCircle className="w-4 h-4 text-primary" />
              Select Changes to Apply
            </h4>

            {sortedCoreSections.map(id => {
              const autoExpand = id === topSectionId && sectionDelta[id] > 0;
              if (id === 'summary') return (
                <Fragment key="summary">
                  <SectionRevealWrapper revealed={revealedSections.has('summary') || revealedSections.size === 0} title={SECTION_LABELS.summary}>
                    <SectionChangeCard
                      sectionId="summary"
                      title={SECTION_LABELS.summary}
                      enabled={enabledSections.includes('summary')}
                      onToggle={() => toggleSection('summary')}
                      impactScore={sectionDelta.summary}
                      changesSummary={summaryChangesSummary}
                      originalText={originalResume?.summary || ''}
                      tailoredText={tailorResult.summary}
                      onRegenerate={onRegenerate}
                      defaultExpanded={autoExpand}
                      preview={<p className="text-muted-foreground leading-relaxed">{tailorResult.summary}</p>}
                    />
                  </SectionRevealWrapper>
                  {preValidatorResult && issueMap.get('summary') && (
                    <SectionIssueCallouts sectionId="summary" issueIndices={issueMap.get('summary')!} issues={preValidatorResult.issues} dismissedIssueIndices={dismissedIssueIndices} onDismissIssue={onDismissIssue} />
                  )}
                </Fragment>
              );
              if (id === 'skills') return (
                <Fragment key="skills">
                  <SectionRevealWrapper revealed={revealedSections.has('skills') || revealedSections.size === 0} title={SECTION_LABELS.skills}>
                    <SectionChangeCard
                      sectionId="skills"
                      title={SECTION_LABELS.skills}
                      enabled={enabledSections.includes('skills')}
                      onToggle={() => toggleSection('skills')}
                      impactScore={sectionDelta.skills}
                      changesSummary={skillsChangesSummary}
                      originalSkills={originalResume?.skills || []}
                      tailoredSkills={tailorResult.skills}
                      onRegenerate={onRegenerate}
                      defaultExpanded={autoExpand}
                      preview={
                        <div className="flex flex-wrap gap-2">
                          {tailorResult.skills.slice(0, 10).map((skill, i) => (
                            <Badge key={i} variant="secondary" className="text-xs">{skill}</Badge>
                          ))}
                          {tailorResult.skills.length > 10 && (
                            <Badge variant="outline" className="text-xs">+{tailorResult.skills.length - 10} more</Badge>
                          )}
                        </div>
                      }
                    />
                  </SectionRevealWrapper>
                  {preValidatorResult && issueMap.get('skills') && (
                    <SectionIssueCallouts sectionId="skills" issueIndices={issueMap.get('skills')!} issues={preValidatorResult.issues} dismissedIssueIndices={dismissedIssueIndices} onDismissIssue={onDismissIssue} />
                  )}
                </Fragment>
              );
              if (id === 'experience') return (
                <Fragment key="experience">
                  <SectionRevealWrapper revealed={revealedSections.has('experience') || revealedSections.size === 0} title={SECTION_LABELS.experience}>
                    <SectionChangeCard
                      sectionId="experience"
                      title={SECTION_LABELS.experience}
                      enabled={enabledSections.includes('experience')}
                      onToggle={() => toggleSection('experience')}
                      impactScore={sectionDelta.experience}
                      changesSummary={experienceChangesSummary}
                      bulletTransformations={tailorResult.bulletTransformations}
                      onBulletReject={onBulletReject}
                      onRegenerate={onRegenerate}
                      defaultExpanded={autoExpand}
                      preview={
                        <ul className="space-y-2">
                          {tailorResult.experience.slice(0, 2).map((exp, i) => (
                            <li key={i} className="text-muted-foreground">
                              <span className="font-medium text-foreground">{exp.position}</span>
                              <span className="text-xs"> @ {exp.company}</span>
                            </li>
                          ))}
                        </ul>
                      }
                    />
                  </SectionRevealWrapper>
                  {preValidatorResult && issueMap.get('experience') && (
                    <SectionIssueCallouts sectionId="experience" issueIndices={issueMap.get('experience')!} issues={preValidatorResult.issues} dismissedIssueIndices={dismissedIssueIndices} onDismissIssue={onDismissIssue} />
                  )}
                </Fragment>
              );
              if (id === 'education') return (
                <Fragment key="education">
                  <SectionRevealWrapper revealed={revealedSections.has('education') || revealedSections.size === 0} title={SECTION_LABELS.education}>
                    <SectionChangeCard
                      sectionId="education"
                      title={SECTION_LABELS.education}
                      enabled={enabledSections.includes('education')}
                      onToggle={() => toggleSection('education')}
                      impactScore={sectionDelta.education}
                      changesSummary={`${tailorResult.education.length} entries refined`}
                      onRegenerate={onRegenerate}
                      defaultExpanded={autoExpand}
                      preview={
                        <ul className="space-y-1">
                          {tailorResult.education.map((edu, i) => (
                            <li key={i} className="text-muted-foreground text-sm">
                              {formatDegreeAndField(edu.degree, edu.field)}{edu.institution ? ` - ${edu.institution}` : ''}
                            </li>
                          ))}
                        </ul>
                      }
                    />
                  </SectionRevealWrapper>
                  {preValidatorResult && issueMap.get('education') && (
                    <SectionIssueCallouts sectionId="education" issueIndices={issueMap.get('education')!} issues={preValidatorResult.issues} dismissedIssueIndices={dismissedIssueIndices} onDismissIssue={onDismissIssue} />
                  )}
                </Fragment>
              );
              return null;
            })}

            {tailorResult.projects && tailorResult.projects.length > 0 && (
              <>
                <SectionRevealWrapper revealed={revealedSections.has('projects') || revealedSections.size === 0} title={SECTION_LABELS.projects}>
                  <SectionChangeCard
                    sectionId="projects"
                    title={SECTION_LABELS.projects}
                    enabled={enabledSections.includes('projects')}
                    onToggle={() => toggleSection('projects')}
                    impactScore={5}
                    changesSummary={`${tailorResult.projects.length} projects optimized`}
                    onRegenerate={onRegenerate}
                    preview={
                      <ul className="space-y-1">
                        {tailorResult.projects.map((p, i) => (
                          <li key={i} className="text-muted-foreground text-sm">
                            <span className="font-medium text-foreground">{p.name}</span>
                          </li>
                        ))}
                      </ul>
                    }
                  />
                </SectionRevealWrapper>
                {preValidatorResult && issueMap.get('projects') && (
                  <SectionIssueCallouts sectionId="projects" issueIndices={issueMap.get('projects')!} issues={preValidatorResult.issues} dismissedIssueIndices={dismissedIssueIndices} onDismissIssue={onDismissIssue} />
                )}
              </>
            )}

            {tailorResult.certifications && tailorResult.certifications.length > 0 && (
              <>
                <SectionRevealWrapper revealed={revealedSections.has('certifications') || revealedSections.size === 0} title={SECTION_LABELS.certifications}>
                  <SectionChangeCard
                    sectionId="certifications"
                    title={SECTION_LABELS.certifications}
                    enabled={enabledSections.includes('certifications')}
                    onToggle={() => toggleSection('certifications')}
                    impactScore={3}
                    changesSummary={`${tailorResult.certifications.length} certifications refined`}
                    onRegenerate={onRegenerate}
                    preview={
                      <ul className="space-y-1">
                        {tailorResult.certifications.map((c, i) => (
                          <li key={i} className="text-muted-foreground text-sm">{c.name} — {c.issuer}</li>
                        ))}
                      </ul>
                    }
                  />
                </SectionRevealWrapper>
                {preValidatorResult && issueMap.get('certifications') && (
                  <SectionIssueCallouts sectionId="certifications" issueIndices={issueMap.get('certifications')!} issues={preValidatorResult.issues} dismissedIssueIndices={dismissedIssueIndices} onDismissIssue={onDismissIssue} />
                )}
              </>
            )}
          </div>

          {/* ATS Keyword Match List — deterministic from backend */}
          {!!(tailorResult.atsAnalysis?.matchedKeywords?.length || tailorResult.atsAnalysis?.unmatchedKeywords?.length || tailorResult.atsAnalysis?.criticalKeywords?.length) && (
            <KeywordMatchList
              matchedKeywords={tailorResult.atsAnalysis?.matchedKeywords}
              unmatchedKeywords={tailorResult.atsAnalysis?.unmatchedKeywords}
              criticalKeywords={tailorResult.atsAnalysis?.criticalKeywords}
              missingSkills={tailorResult.missingSkills}
            />
          )}

          {/* Pre-validation feedback — shown while loading or once result arrives */}
          {(isPreValidating || preValidatorResult) && (
            <div className="rounded-xl border border-border bg-card p-4 space-y-3">
              <div className="flex items-center gap-2">
                <Shield className="w-4 h-4 text-primary shrink-0" />
                <h4 className="font-semibold text-sm flex-1">Validator Check</h4>
                {isPreValidating && !preValidatorResult && (
                  <span className="flex items-center gap-1.5 text-xs text-muted-foreground">
                    <MiniSpinner size={14} />
                    Checking…
                  </span>
                )}
              </div>

              {preValidatorResult && (
                <>
                  {/* Score + verdict row */}
                  <div className="flex items-center gap-2 flex-wrap">
                    <span className={cn(
                      'text-xs font-semibold px-2.5 py-0.5 rounded-full',
                      preValidatorResult.verdict === 'strong'
                        ? 'bg-success/10 text-success'
                        : preValidatorResult.verdict === 'average'
                          ? 'bg-warning/10 text-warning'
                          : 'bg-destructive/10 text-destructive'
                    )}>
                      {preValidatorResult.verdict === 'strong'
                        ? 'Strong'
                        : preValidatorResult.verdict === 'average'
                          ? 'Average'
                          : 'Weak'}
                    </span>
                    <span className="text-sm font-bold tabular-nums">{preValidatorResult.score}%</span>
                    <span className="text-xs text-muted-foreground">keyword match · Verified</span>
                  </div>

                  {/* Missing keywords */}
                  {preValidatorResult.missing_keywords.length > 0 && (
                    <div>
                      <p className="text-xs font-medium text-muted-foreground mb-1.5">
                        Missing keywords — consider adding these before applying:
                      </p>
                      <div className="flex flex-wrap gap-1.5">
                        {preValidatorResult.missing_keywords.map((kw, i) => (
                          <span
                            key={i}
                            className="text-xs bg-destructive/10 text-destructive px-2 py-0.5 rounded-full border border-destructive/20 font-medium"
                          >
                            {kw}
                          </span>
                        ))}
                      </div>
                    </div>
                  )}

                  {/* Fix suggestions — shown between missing keywords and global issues */}
                  {(isGeneratingFixes || fixSuggestions !== null) && (
                    <div className="space-y-2 pt-1">
                      <p className="text-xs font-semibold text-foreground flex items-center gap-1.5">
                        <Sparkles className="w-3.5 h-3.5 text-primary" />
                        AI suggestions to improve your match
                        {isGeneratingFixes && (
                          <MiniSpinner size={12} className="ml-1 text-muted-foreground" />
                        )}
                      </p>
                      {!isGeneratingFixes && fixSuggestions !== null && fixSuggestions.length === 0 && (
                        <div className="flex items-center gap-2.5 px-3 py-2.5 rounded-lg bg-success/10 border border-success/20">
                          <CheckCircle className="w-4 h-4 text-success shrink-0" />
                          <p className="text-xs text-success font-medium">No critical issues found — your resume is well optimized for this role</p>
                        </div>
                      )}
                      {fixSuggestions?.map((fix) => (
                        <FixSuggestionCard
                          key={`${fix.type}-${fix.after}-${fix.target_id ?? ''}`}
                          fix={fix}
                          onApply={() => onApplyFix(fix)}
                        />
                      ))}
                    </div>
                  )}

                  {/* Score-awareness note */}
                  {appliedFixes.length > 0 && (
                    <p className="text-[11px] text-muted-foreground bg-muted/60 rounded-md px-2.5 py-1.5 leading-snug">
                      Applied improvements will be reflected in your final score after you click Apply.
                    </p>
                  )}

                  {/* Global issues (not tied to any specific section) */}
                  {(issueMap.get('global') ?? []).length > 0 && (
                    <SectionIssueCallouts
                      sectionId="summary"
                      issueIndices={issueMap.get('global')!}
                      issues={preValidatorResult.issues}
                      dismissedIssueIndices={dismissedIssueIndices}
                      onDismissIssue={onDismissIssue}
                    />
                  )}
                </>
              )}
            </div>
          )}

          {/* Apply */}
          <div className="flex flex-col gap-2 pt-2">
            {tailorResult?.overallScore && tailorResult.overallScore.after > tailorResult.overallScore.before && (
              <p className="text-xs text-muted-foreground text-center">
                Your score will improve from {tailorResult.overallScore.before}%{' '}
                <span aria-hidden="true">→</span>{' '}
                {tailorResult.overallScore.after}%
              </p>
            )}
            <div className="flex flex-col sm:flex-row flex-wrap gap-2">
              <Button
                variant={discardConfirm ? 'destructive' : 'outline'}
                className="flex-1 min-w-0 min-h-[48px]"
                onClick={handleDiscardClick}
              >
                <X className="w-4 h-4 mr-2" />
                {discardConfirm ? 'Confirm discard?' : 'Discard'}
              </Button>
              <Button
                variant="outline"
                className="flex-1 min-w-0 min-h-[48px]"
                onClick={onPreview}
                disabled={enabledSections.length === 0}
              >
                <Eye className="w-4 h-4 mr-2" /> Preview
              </Button>
              <Button
                className="flex-1 min-w-0 min-h-[48px] font-semibold shadow-soft-sm"
                onClick={onApplyChanges}
                disabled={enabledSections.length === 0 || isApplying}
              >
                {isApplying ? (
                  <MiniSpinner size={16} className="mr-2" />
                ) : (
                  <CheckCircle className="w-4 h-4 mr-2" />
                )}
                {isApplying ? 'Saving...' : 'Apply Improvements'}
              </Button>
            </div>
            <div className="flex flex-col gap-0.5 items-center">
              <p className="text-xs text-muted-foreground text-center">This will save an optimized copy — your original is always kept safe</p>
              <p className="text-[11px] text-muted-foreground/70 text-center">You can always edit your resume later</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useMemo, useCallback, useRef, useEffect } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { Wand2, ArrowLeft, Briefcase } from 'lucide-react';
import { toast } from 'sonner';
import { useShallow } from 'zustand/react/shallow';

import { useResumeStore } from '@/store/resumeStore';
import { useResumes, dbToResumeData, type DatabaseResume } from '@/hooks/useResumes';
import { useJob, type Job } from '@/hooks/useJobs';
import { ImportJobSheet } from '@/components/jobs/ImportJobSheet';
import { useAuth } from '@/hooks/useAuth';
import { useAIAction } from '@/hooks/useAIAction';
import { useImportJob } from '@/hooks/useImportJob';
import { useRedactedResume } from '@/hooks/useRedactedResume';
import { useAppwriteTailoredIds } from '@/hooks/useTailorHistory';
import { isTailoredResume } from '@/lib/resumeLineage';
import { useQueryClient } from '@tanstack/react-query';
import { tailorResumeWithProgress, type TailorIntensity } from '@/lib/aiTailor';
import { buildMergedResume } from '@/lib/tailorMerge';
import { databases, DATABASE_ID, ID } from '@/lib/appwrite';
import { COLLECTIONS } from '@/lib/appwrite-collections';
import { invalidateAiCreditQueries } from '@/lib/invalidate-ai-credit-queries';
import { aiErrorToastMessage, isAIError } from '@/lib/aiErrorParser';
import { activityTracker } from '@/lib/activityTracker';
import { haptics } from '@/lib/haptics';
import { cn } from '@/lib/utils';

import {
  type SuperTailorResult,
  type TailorProgress,
  type EnhancedTailorProgress,
  type TailorSectionId,
  type ResumeData,
} from '@/types/resume';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Button } from '@/components/ui/button';

import { ResumeChip } from '@/components/job-match/ResumeChip';
import { JobInputArea } from '@/components/job-match/JobInputArea';
import { JobPreviewCard } from '@/components/job-match/JobPreviewCard';
import { MatchAnalysisSummary, extractKeywords, computeMatch } from '@/components/job-match/MatchAnalysisSummary';
import { JobMatchAdvancedOptions } from '@/components/job-match/JobMatchAdvancedOptions';
import { JobMatchStickyFooter } from '@/components/job-match/JobMatchStickyFooter';
import { JobMatchProgressStage } from '@/components/job-match/JobMatchProgressStage';
import { JobMatchHistoryList } from '@/components/job-match/JobMatchHistoryList';
import { JobMatchSavedJobsList } from '@/components/job-match/JobMatchSavedJobsList';
import { TailoringHubLanding } from '@/components/tailoring-hub/TailoringHubLanding';
import { isSyntheticSavedJobId } from '@/hooks/useSavedJobPostings';
import '@/components/job-match/job-match-workspace.css';
import { saveTailorJobDescriptionForResume } from '@/lib/tailorJobContext';

type AnyTailorProgress = TailorProgress | EnhancedTailorProgress;

const DEFAULT_SECTIONS: TailorSectionId[] = [
  'summary', 'skills', 'experience', 'education', 'projects', 'certifications', 'awards',
];

type HubView = 'hub' | 'workspace';

function shouldOpenWorkspaceDirectly(params: URLSearchParams, preloadedDesc: string): boolean {
  return Boolean(
    params.get('jobId') ||
      params.get('mode') === 'workspace' ||
      params.get('tailor') === '1' ||
      (preloadedDesc && preloadedDesc.trim().length > 0),
  );
}

export default function JobMatchWorkspacePage() {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();
  const { user } = useAuth();
  const queryClient = useQueryClient();

  const {
    currentResumeId,
    jobDescription,
    setJobDescription,
    addTailorHistory,
    setCurrentResumeId,
  } = useResumeStore(
    useShallow((state) => ({
      currentResumeId: state.currentResumeId,
      jobDescription: state.jobDescription,
      setJobDescription: state.setJobDescription,
      addTailorHistory: state.addTailorHistory,
      setCurrentResumeId: state.setCurrentResumeId,
    })),
  );

  const { data: allResumes, isLoading: resumesLoading } = useResumes();
  const { data: persistedTailoredIds = new Set<string>() } = useAppwriteTailoredIds();

  const isLikelyTailoredResume = useCallback((resume: DatabaseResume, tailoredIds: Set<string>) => (
    isTailoredResume(resume, tailoredIds)
  ), []);

  const currentResume = useMemo(() => {
    const found = allResumes?.find((r: DatabaseResume) => r.$id === currentResumeId);
    return found ? dbToResumeData(found) : null;
  }, [allResumes, currentResumeId]);

  const selectedResumeTitle = useMemo(() => {
    const found = allResumes?.find((r: DatabaseResume) => r.$id === currentResumeId);
    return found?.title ?? null;
  }, [allResumes, currentResumeId]);

  // Pre-fill from query params
  const jobIdParam = searchParams.get('jobId');
  const preloadedDesc = searchParams.get('job') || '';
  const preloadedTitle = searchParams.get('title') || '';
  const preloadedCompany = searchParams.get('company') || '';
  const preloadedUrl = searchParams.get('url') || '';

  const [hubView, setHubView] = useState<HubView>(() =>
    shouldOpenWorkspaceDirectly(searchParams, preloadedDesc) ? 'workspace' : 'hub',
  );

  const { data: preloadedJob } = useJob(jobIdParam);

  const [jobUrl, setJobUrl] = useState('');
  const [parsedJobInfo, setParsedJobInfo] = useState<{ title: string; company: string } | null>(null);
  const [intensity, setIntensity] = useState<TailorIntensity>('moderate');
  const [enabledSections, setEnabledSections] = useState<TailorSectionId[]>(DEFAULT_SECTIONS);
  const [isTailoring, setIsTailoring] = useState(false);
  const [progress, setProgress] = useState<TailorProgress | EnhancedTailorProgress | null>(null);
  const [tailorError, setTailorError] = useState<string | null>(null);
  const [showResumePicker, setShowResumePicker] = useState(false);
  const [jobInputActiveTab, setJobInputActiveTab] = useState<'paste' | 'url'>('paste');
  const [importJobOpen, setImportJobOpen] = useState(false);

  const abortRef = useRef<AbortController | null>(null);
  const { execute: executeAI } = useAIAction({ operation: 'tailor' });
  const importJob = useImportJob();
  const redactedResume = useRedactedResume(currentResume as ResumeData | null);

  // Auto-select a MASTER resume on load.
  // Tailored copies are detected via persisted tailor_history, schema-backed metadata
  // when present, and a title suffix heuristic as a last resort.
  // If the current selection is already a known master resume, leave it alone.
  // Otherwise (unset or is a tailored copy), find the source resume or most-recent master.
  useEffect(() => {
    if (!allResumes || allResumes.length === 0) return;
    const sortByRecent = (arr: DatabaseResume[]) =>
      [...arr].sort(
        (a, b) =>
          new Date(b.$updatedAt ?? b.$createdAt ?? 0).getTime() -
          new Date(a.$updatedAt ?? a.$createdAt ?? 0).getTime(),
      );
    const tailoredIds = new Set<string>([
      ...(
        useResumeStore.getState().tailorHistory
          .map((h) => h.tailoredResumeId)
          .filter(Boolean) as string[]
      ),
      ...persistedTailoredIds,
    ]);
    const currentDb = allResumes.find((r: DatabaseResume) => r.$id === currentResumeId);
    const isTailored = currentDb ? isLikelyTailoredResume(currentDb, tailoredIds) : false;
    if (currentDb && !isTailored) return; // already a master — done
    const masters = allResumes.filter((r: DatabaseResume) => !isLikelyTailoredResume(r, tailoredIds));
    const target = sortByRecent(masters)[0] ?? sortByRecent(allResumes)[0];
    if (target) setCurrentResumeId(target.$id);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [allResumes, currentResumeId, isLikelyTailoredResume, persistedTailoredIds, setCurrentResumeId]);

  // Pre-fill job description/info from query params
  useEffect(() => {
    if (preloadedDesc && !jobDescription) setJobDescription(preloadedDesc);
    if (preloadedTitle && preloadedCompany) {
      setParsedJobInfo({ title: preloadedTitle, company: preloadedCompany });
    }
    if (preloadedUrl && !jobUrl) setJobUrl(preloadedUrl);
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Pre-fill from saved job
  useEffect(() => {
    if (!preloadedJob) return;
    const desc = [preloadedJob.description, preloadedJob.requirements].filter(Boolean).join('\n\n');
    if (desc && !jobDescription) setJobDescription(desc);
    if (preloadedJob.source_url) setJobUrl(preloadedJob.source_url);
    setParsedJobInfo({ title: preloadedJob.title, company: preloadedJob.company });
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [preloadedJob]);

  useEffect(() => {
    activityTracker.setActiveFeature('Tailoring Hub');
    return () => activityTracker.setActiveFeature(null);
  }, []);

  const resumeText = useMemo(() => {
    if (!currentResume) return '';
    return [
      currentResume.summary,
      ...currentResume.experience.map(
        (e) => `${e.position} ${e.company} ${e.description} ${e.achievements.join(' ')}`,
      ),
      ...currentResume.education.map((e) => `${e.degree} ${e.field} ${e.institution}`),
      ...currentResume.skills,
    ]
      .filter(Boolean)
      .join(' ');
  }, [currentResume]);

  const canTailor = Boolean(currentResumeId && jobDescription.trim().length > 50);

  const jobSkills = useMemo(
    () => (jobDescription.trim().length > 50 ? extractKeywords(jobDescription, 15) : []),
    [jobDescription],
  );

  const matchScoreBefore = useMemo(() => {
    if (!jobDescription.trim() || !resumeText.trim()) return undefined;
    return computeMatch(jobDescription, resumeText).score;
  }, [jobDescription, resumeText]);

  const enterWorkspace = useCallback((nextParams?: Record<string, string>) => {
    setHubView('workspace');
    const merged = new URLSearchParams(searchParams);
    merged.set('mode', 'workspace');
    if (nextParams) {
      Object.entries(nextParams).forEach(([key, value]) => merged.set(key, value));
    }
    setSearchParams(merged, { replace: true });
  }, [searchParams, setSearchParams]);

  const exitToHub = useCallback(() => {
    setHubView('hub');
    const merged = new URLSearchParams(searchParams);
    merged.delete('mode');
    merged.delete('tailor');
    merged.delete('jobId');
    merged.delete('job');
    merged.delete('title');
    merged.delete('company');
    setSearchParams(merged, { replace: true });
  }, [searchParams, setSearchParams]);

  const applyImportedJob = useCallback((job: {
    title: string;
    company: string;
    description?: string;
    requirements?: string;
    source_url?: string | null;
  }, jobId?: string) => {
    const desc = [job.description, job.requirements].filter(Boolean).join('\n\n');
    if (desc) setJobDescription(desc);
    setParsedJobInfo({ title: job.title, company: job.company });
    if (job.source_url) setJobUrl(job.source_url);
    setJobInputActiveTab('paste');
    enterWorkspace(jobId ? { jobId } : undefined);
  }, [enterWorkspace, setJobDescription]);

  const handleSelectSavedJob = useCallback((job: Job) => {
    haptics.selection();
    applyImportedJob(
      {
        title: job.title,
        company: job.company,
        description: job.description,
        requirements: job.requirements,
        source_url: job.source_url,
      },
      isSyntheticSavedJobId(job.id) ? undefined : job.id,
    );
    toast.success('Job loaded — review the description and tailor when ready.');
  }, [applyImportedJob]);

  const handleStartTailoring = useCallback(() => {
    enterWorkspace();
  }, [enterWorkspace]);

  const handleFetchUrl = useCallback(async (url: string) => {
    if (!user) {
      toast.error('Still signing you in — please try again in a moment.');
      return;
    }
    try {
      const result = await importJob.mutateAsync(url);
      const { job } = result;
      applyImportedJob(
        {
          title: job.title,
          company: job.company,
          description: job.description,
          requirements: job.requirements,
          source_url: url,
        },
        result.id,
      );
      toast.success('Job saved — review the description below.');
    } catch (err) {
      const msg =
        err instanceof Error && err.message && err.message.length < 150 && err.message !== 'Import failed'
          ? err.message
          : 'Could not fetch job details — paste the description manually.';
      toast.error(msg);
    }
  }, [applyImportedJob, importJob, user]);

  const handleTailor = useCallback(async () => {
    if (!currentResume || !jobDescription.trim() || !user) {
      toast.error('Select a resume and add a job description to continue.');
      return;
    }
    if (jobDescription.trim().length < 50) {
      toast.error('Job description is too short — paste the full job posting for best results.');
      return;
    }

    haptics.medium();
    setIsTailoring(true);
    setTailorError(null);
    setProgress(null);

    const abort = new AbortController();
    abortRef.current = abort;

    try {
      let tailorResult: SuperTailorResult | null = null;
      const originalResume = currentResume;

      const aiRan = await executeAI(async () => {
        tailorResult = await tailorResumeWithProgress(
          redactedResume ?? currentResume,
          jobDescription,
          (p: AnyTailorProgress) => setProgress(p),
          intensity,
          abort.signal,
          localStorage.getItem('wr-tailor-custom-instructions') || undefined,
        );
        return tailorResult;
      });

      if (abort.signal.aborted) return;
      if (!aiRan || !tailorResult || !originalResume) {
        setTailorError('Tailoring could not complete. Please try again in a moment.');
        return;
      }

      // Compute keyword-overlap score BEFORE merging (used as fallback when AI returns overallScore: null)
      const resumeTextBefore = [
        originalResume.summary,
        ...originalResume.experience.map(
          (e) => `${e.position} ${e.company} ${e.description} ${e.achievements.join(' ')}`,
        ),
        ...originalResume.education.map((e) => `${e.degree} ${e.field} ${e.institution}`),
        ...originalResume.skills,
      ].filter(Boolean).join(' ');
      const scoreBefore = computeMatch(jobDescription, resumeTextBefore).score;

      // Build merged resume
      const merged = buildMergedResume(originalResume, tailorResult as SuperTailorResult, enabledSections);
      const resumeTextAfter = [
        merged.summary,
        ...merged.experience.map(
          (e) => `${e.position} ${e.company} ${e.description} ${e.achievements.join(' ')}`,
        ),
        ...merged.education.map((e) => `${e.degree} ${e.field} ${e.institution}`),
        ...merged.skills,
      ].filter(Boolean).join(' ');
      const scoreAfter = computeMatch(jobDescription, resumeTextAfter).score;
      const jobTitle = parsedJobInfo?.title ?? 'Job';
      const company = parsedJobInfo?.company ?? '';

      // Save as new resume document
      const newTitle = `${originalResume.contactInfo.fullName || 'Resume'} — ${jobTitle}${company ? ` @ ${company}` : ''} (Tailored)`;
      const doc = await databases.createDocument(
        DATABASE_ID,
        COLLECTIONS.resumes,
        ID.unique(),
        {
          user_id: user.id,
          title: newTitle,
          parent_resume_id: currentResumeId ?? undefined,
          contact_info: JSON.stringify(merged.contactInfo),
          summary: merged.summary,
          experience: JSON.stringify(merged.experience),
          education: JSON.stringify(merged.education),
          skills: JSON.stringify(merged.skills),
          certifications: JSON.stringify(merged.certifications ?? []),
          projects: JSON.stringify(merged.projects ?? []),
          awards: JSON.stringify(merged.awards ?? []),
          template: merged.templateId || 'modern',
        },
      );
      const newResumeId = (doc as { $id: string }).$id;

      // Persist tailor history
      // Prefer AI-computed overallScore; fall back to keyword-overlap scores if null.
      const resultScore = (tailorResult as SuperTailorResult).overallScore;
      const scoreBeforeAfter = {
        before: resultScore?.before ?? scoreBefore,
        after: resultScore?.after ?? scoreAfter,
      };
      addTailorHistory(
        {
          jobTitle,
          company,
          jobDescription,
          jobUrl: jobUrl || undefined,
          tailoredResumeId: newResumeId,
          tailorResult: tailorResult as SuperTailorResult,
          scoreBeforeAfter,
          appliedSections: enabledSections,
        },
        currentResumeId ?? undefined,
      );

      // Invalidate credits and resumes cache
      await invalidateAiCreditQueries(queryClient);
      queryClient.invalidateQueries({ queryKey: ['resumes'] });
      queryClient.invalidateQueries({ queryKey: ['saved-job-postings'] });
      queryClient.invalidateQueries({ queryKey: ['tailor-history-list'] });

      haptics.success();
      toast.success('Tailored CV created!');

      // Navigate first, then fire-and-forget Appwrite history write (E-7: pass enrichment state)
      navigate(`/tailoring-hub/result/${newResumeId}`, {
        state: {
          jobTitle,
          company,
          jobUrl: jobUrl || null,
          scoreBeforeAfter,
          appliedSections: enabledSections,
          intensity,
        },
      });

      saveTailorJobDescriptionForResume(newResumeId, jobDescription);

      // Clear persisted job description so workspace starts fresh next session
      setJobDescription('');

      // E-6: Persist to Appwrite tailor_history (fire-and-forget, non-blocking)
      databases.createDocument(
        DATABASE_ID,
        COLLECTIONS.tailor_history,
        ID.unique(),
        {
          user_id: user.id,
          job_title: jobTitle,
          company: company || '',
          job_url: jobUrl || null,
          tailored_resume_id: newResumeId,
          source_resume_id: currentResumeId ?? null,
          score_before: scoreBeforeAfter.before,
          score_after: scoreBeforeAfter.after,
          applied_sections: JSON.stringify(enabledSections),
          intensity,
          status: 'completed',
          job_description: jobDescription.slice(0, 5000),
        },
      ).catch((err: unknown) => {
        console.warn('[TailoringHub] tailor_history write failed (non-blocking):', err);
        toast.warning('Your tailored resume was saved, but it may not show in Tailoring history until history storage is fixed.');
      });
    } catch (err: unknown) {
      if (abort.signal.aborted) return;
      const msg = isAIError(err)
        ? aiErrorToastMessage({ code: err.code, message: err.message, status: err.status })
        : (err instanceof Error ? err.message : 'Something went wrong. Please try again.');
      setTailorError(msg);
      haptics.error();
      toast.error(msg);
    } finally {
      if (!abort.signal.aborted) {
        setIsTailoring(false);
        setProgress(null);
      }
    }
  }, [
    currentResume,
    jobDescription,
    user,
    enabledSections,
    intensity,
    parsedJobInfo,
    jobUrl,
    executeAI,
    redactedResume,
    addTailorHistory,
    currentResumeId,
    queryClient,
    navigate,
  ]);

  const handleAbort = () => {
    abortRef.current?.abort();
    setIsTailoring(false);
    setProgress(null);
    toast.info('Tailoring cancelled.');
  };

  return (
    <div className="jmw-page">
      {/* Header */}
      <div className="jmw-header">
        <div className="jmw-header__glow" aria-hidden />
        <div className="jmw-header__inner">
          <button
            type="button"
            onClick={() => (hubView === 'workspace' ? exitToHub() : navigate(-1))}
            className="flex items-center justify-center w-9 h-9 rounded-xl text-muted-foreground hover:text-foreground hover:bg-muted/40 transition-colors shrink-0"
            aria-label={hubView === 'workspace' ? 'Back to hub overview' : 'Go back'}
          >
            <ArrowLeft className="w-4 h-4" aria-hidden />
          </button>
          <div className="flex items-center gap-2 min-w-0 flex-1">
            <span className="flex items-center justify-center w-8 h-8 rounded-xl bg-primary/12 border border-primary/20 shrink-0">
              <Wand2 className="w-4 h-4 text-primary" aria-hidden />
            </span>
            <div className="min-w-0">
              <p className="text-[10px] font-semibold uppercase tracking-wider text-primary/80 leading-none">
                AI Tailoring
              </p>
              <h1 className="text-sm font-bold text-foreground leading-snug truncate">
                {hubView === 'hub' ? 'Tailoring Hub' : 'New tailoring session'}
              </h1>
            </div>
          </div>
          {hubView === 'workspace' && parsedJobInfo && (
            <div className="hidden sm:flex items-center gap-1.5 shrink-0 max-w-[12rem]">
              <Briefcase className="w-3.5 h-3.5 text-muted-foreground shrink-0" aria-hidden />
              <span className="text-xs text-muted-foreground truncate">
                {parsedJobInfo.title}
                {parsedJobInfo.company ? ` @ ${parsedJobInfo.company}` : ''}
              </span>
            </div>
          )}
        </div>
      </div>

      {/* Progress overlay */}
      {isTailoring && (
        <JobMatchProgressStage
          progress={progress}
          jobTitle={parsedJobInfo?.title}
          company={parsedJobInfo?.company}
          resumeTitle={selectedResumeTitle ?? undefined}
          matchScoreBefore={matchScoreBefore}
          onCancel={handleAbort}
        />
      )}

      {/* Scrollable body */}
      <div className="jmw-body">
        {hubView === 'hub' ? (
          <TailoringHubLanding
            persistedTailoredIds={persistedTailoredIds}
            onStartTailoring={handleStartTailoring}
            onImportJob={() => setImportJobOpen(true)}
            onSelectSavedJob={handleSelectSavedJob}
          />
        ) : (
        <div className="jmw-content">
          <div className="jmw-workflow-steps" aria-label="Tailoring steps">
            <div className="jmw-workflow-step" data-done={currentResumeId ? 'true' : 'false'}>
              <span className="jmw-workflow-step__num">1</span>
              <span className="jmw-workflow-step__label">Pick resume</span>
            </div>
            <div className="jmw-workflow-step" data-done={jobDescription.trim().length > 50 ? 'true' : 'false'}>
              <span className="jmw-workflow-step__num">2</span>
              <span className="jmw-workflow-step__label">Add job details</span>
            </div>
            <div className="jmw-workflow-step" data-done={canTailor ? 'true' : 'false'}>
              <span className="jmw-workflow-step__num">3</span>
              <span className="jmw-workflow-step__label">Tune & create</span>
            </div>
          </div>

          <div className="jmw-content__left">
            <div className="jmw-panel shrink-0">
              <div className="jmw-panel__head">
                <p className="jmw-panel__title">Source resume</p>
              </div>
              <div className="p-3">
                {showResumePicker ? (
                  <div className="flex flex-col gap-2">
                    <Select
                      value={currentResumeId ?? ''}
                      onValueChange={(val) => {
                        setCurrentResumeId(val);
                        setShowResumePicker(false);
                        haptics.selection();
                      }}
                    >
                      <SelectTrigger className="h-11 rounded-xl text-sm">
                        <SelectValue placeholder="Choose a resume…" />
                      </SelectTrigger>
                      <SelectContent>
                        {allResumes?.map((r: DatabaseResume) => (
                          <SelectItem key={r.$id} value={r.$id}>
                            {r.title || 'Untitled Resume'}
                          </SelectItem>
                        ))}
                      </SelectContent>
                    </Select>
                    <Button
                      variant="ghost"
                      size="sm"
                      className="self-start text-xs"
                      onClick={() => setShowResumePicker(false)}
                    >
                      Cancel
                    </Button>
                  </div>
                ) : (
                  <ResumeChip
                    title={selectedResumeTitle}
                    isLoading={resumesLoading}
                    onClick={() => setShowResumePicker(true)}
                    className="border-0 bg-transparent p-0 shadow-none hover:shadow-none min-h-0"
                  />
                )}
              </div>
            </div>

            <JobInputArea
              jobDescription={jobDescription}
              jobUrl={jobUrl}
              onJobDescriptionChange={setJobDescription}
              onJobUrlChange={setJobUrl}
              onFetchUrl={handleFetchUrl}
              isFetchingUrl={importJob.isPending}
              initialTab="paste"
              activeTab={jobInputActiveTab}
              onActiveTabChange={setJobInputActiveTab}
              fillHeight
            />

            {parsedJobInfo && (
              <JobPreviewCard
                title={parsedJobInfo.title}
                company={parsedJobInfo.company}
                jobUrl={jobUrl || undefined}
                description={jobDescription || undefined}
                skills={jobSkills.length > 0 ? jobSkills : undefined}
              />
            )}

            {tailorError && (
              <div className={cn(
                'flex items-start gap-3 rounded-xl border border-destructive/30 bg-destructive/8 px-4 py-3 shrink-0',
              )}>
                <div>
                  <p className="text-sm font-medium text-destructive">Tailoring failed</p>
                  <p className="text-xs text-destructive/80 mt-0.5 leading-relaxed">{tailorError}</p>
                </div>
              </div>
            )}
          </div>

          <div className="jmw-content__right">
            <div className="jmw-content__right-scroll">
              {jobDescription.trim().length > 50 && currentResume && (
                <MatchAnalysisSummary
                  jobDescription={jobDescription}
                  resumeText={resumeText}
                />
              )}

              <JobMatchAdvancedOptions
                intensity={intensity}
                onIntensityChange={setIntensity}
                enabledSections={enabledSections}
                onSectionsChange={setEnabledSections}
              />

              <JobMatchSavedJobsList
                selectedJobId={jobIdParam}
                onSelectJob={handleSelectSavedJob}
                onImportJob={() => setImportJobOpen(true)}
              />

              <JobMatchHistoryList />
            </div>
          </div>

          {!isTailoring && (
            <JobMatchStickyFooter
              className="jmw-content__footer"
              canTailor={canTailor}
              isTailoring={isTailoring}
              onTailor={handleTailor}
            />
          )}
        </div>
        )}
      </div>
      <ImportJobSheet open={importJobOpen} onOpenChange={setImportJobOpen} />
    </div>
  );
}

import { useParams, useNavigate, useLocation } from 'react-router-dom';
import {
  ArrowLeft,
  CheckCircle2,
  Loader2,
  Briefcase,
  TrendingUp,
  ExternalLink,
} from 'lucide-react';
import { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { Button } from '@/components/ui/button';
import { useResumes, dbToResumeData, type DatabaseResume } from '@/hooks/useResumes';
import { useResumeStore } from '@/store/resumeStore';
import { useShallow } from 'zustand/react/shallow';
import { databases, DATABASE_ID, Query } from '@/lib/appwrite';
import { COLLECTIONS } from '@/lib/appwrite-collections';
import { useQuery } from '@tanstack/react-query';
import { templates } from '@/lib/templateData';
import { TemplateId } from '@/types/resume';
import { cn } from '@/lib/utils';
import { toast } from 'sonner';
import { TailorResumeCompare } from '@/components/job-match/TailorResumeCompare';
import { ScaledResumePage } from '@/components/job-match/ScaledResumePage';
import { TailorResultExportPanel } from '@/components/job-match/TailorResultExportPanel';
import { TailorResultCoverLetterPanel } from '@/components/job-match/TailorResultCoverLetterPanel';
import { TailorQuickPdfExportDialog } from '@/components/job-match/TailorQuickPdfExportDialog';
import { useCoverLetter, parseCoverLetter } from '@/hooks/useCoverLetters';
import {
  resolveTailorJobContext,
  saveCoverLetterPrefill,
  saveTailorJobDescriptionForResume,
  readLinkedCoverLetterForTailoredResume,
  saveLinkedCoverLetterForTailoredResume,
} from '@/lib/tailorJobContext';
import type { SuperTailorResult, TailorSectionId } from '@/types/resume';
import '@/components/job-match/job-match-workspace.css';

interface ResultState {
  jobTitle?: string;
  company?: string;
  jobUrl?: string | null;
  scoreBeforeAfter?: { before: number; after: number };
  appliedSections?: string[];
  intensity?: string;
  coverLetterId?: string;
}

export function resolveTailoringResultState(params: {
  locationState?: ResultState | null;
  tailorHistory: Array<{
    tailoredResumeId?: string | null;
    jobTitle: string;
    company: string;
    jobUrl?: string | null;
    scoreBeforeAfter?: { before: number; after: number };
    appliedSections?: string[];
  }>;
  resumeId?: string;
  appwriteEntry?: Record<string, unknown> | null;
}): ResultState {
  const { locationState, tailorHistory, resumeId, appwriteEntry } = params;
  if (
    locationState &&
    (
      !!locationState.jobTitle ||
      !!locationState.company ||
      !!locationState.jobUrl ||
      !!locationState.scoreBeforeAfter ||
      (locationState.appliedSections?.length ?? 0) > 0
    )
  ) {
    return locationState;
  }

  const entry = tailorHistory.find((item) => item.tailoredResumeId === resumeId);
  if (entry) {
    return {
      jobTitle: entry.jobTitle,
      company: entry.company,
      jobUrl: entry.jobUrl,
      scoreBeforeAfter: entry.scoreBeforeAfter,
      appliedSections: entry.appliedSections,
    };
  }

  if (appwriteEntry) {
    return {
      jobTitle: appwriteEntry.job_title as string | undefined,
      company: appwriteEntry.company as string | undefined,
      jobUrl: appwriteEntry.job_url as string | undefined,
      scoreBeforeAfter: (appwriteEntry.score_before != null && appwriteEntry.score_after != null)
        ? { before: appwriteEntry.score_before as number, after: appwriteEntry.score_after as number }
        : undefined,
      appliedSections: (() => {
        try {
          return appwriteEntry.applied_sections
            ? (JSON.parse(appwriteEntry.applied_sections as string) as string[])
            : undefined;
        } catch {
          console.warn('[TailoringHub] applied_sections parse failed');
          return undefined;
        }
      })(),
    };
  }

  return {};
}

export default function JobMatchResultPage() {
  const { resumeId } = useParams<{ resumeId: string }>();
  const navigate = useNavigate();
  const location = useLocation();
  const { data: allResumes, isLoading } = useResumes();
  const {
    setCurrentResumeId,
    setCurrentResume,
    setSelectedTemplate: setSelectedTemplateStore,
    tailorHistory,
  } = useResumeStore(
    useShallow((s) => ({
      setCurrentResumeId: s.setCurrentResumeId,
      setCurrentResume: s.setCurrentResume,
      setSelectedTemplate: s.setSelectedTemplate,
      tailorHistory: s.tailorHistory,
    })),
  );

  const dbResume = useMemo(
    () => allResumes?.find((r: DatabaseResume) => r.$id === resumeId) ?? null,
    [allResumes, resumeId],
  );
  const resume = useMemo(
    () => (dbResume ? dbToResumeData(dbResume) : null),
    [dbResume],
  );

  const [selectedTemplate, setSelectedTemplate] = useState<TemplateId>(
    () => (dbResume?.template as TemplateId) ?? 'modern',
  );
  const [pdfExportOpen, setPdfExportOpen] = useState(false);
  const [coverLetterDownloadBusy, setCoverLetterDownloadBusy] = useState(false);
  const hasUserPickedRef = useRef(false);
  const handlePickTemplate = useCallback((id: TemplateId) => {
    hasUserPickedRef.current = true;
    setSelectedTemplate(id);
  }, []);

  useEffect(() => {
    if (!dbResume?.template) return;
    if (hasUserPickedRef.current) return;
    const tpl = dbResume.template as TemplateId;
    if (!templates.some((t) => t.id === tpl)) return;
    setSelectedTemplate(tpl);
  }, [dbResume?.template]);

  const tailorHistoryEntry = useMemo(
    () => tailorHistory.find((item) => item.tailoredResumeId === resumeId) ?? null,
    [tailorHistory, resumeId],
  );

  const resultState: ResultState = useMemo(() => resolveTailoringResultState({
    locationState: location.state as ResultState | null,
    tailorHistory,
    resumeId,
  }), [location.state, tailorHistory, resumeId]);

  const { data: appwriteEntry } = useQuery({
    queryKey: ['tailor-history-by-resume', resumeId],
    queryFn: async () => {
      try {
        const res = await databases.listDocuments(DATABASE_ID, COLLECTIONS.tailor_history, [
          Query.equal('tailored_resume_id', [resumeId!]),
          Query.limit(1),
        ]);
        return res.documents[0] ?? null;
      } catch {
        return null;
      }
    },
    enabled: !!resumeId,
    staleTime: 5 * 60 * 1000,
    retry: false,
  });

  const effectiveState: ResultState = useMemo(() => resolveTailoringResultState({
    locationState: Object.keys(resultState).length ? resultState : null,
    tailorHistory: [],
    resumeId,
    appwriteEntry: appwriteEntry as Record<string, unknown> | null,
  }), [appwriteEntry, resultState, resumeId]);

  const jobContext = useMemo(
    () => resolveTailorJobContext({
      jobTitle: effectiveState.jobTitle ?? tailorHistoryEntry?.jobTitle,
      company: effectiveState.company ?? tailorHistoryEntry?.company,
      jobDescription: tailorHistoryEntry?.jobDescription,
      jobUrl: effectiveState.jobUrl ?? tailorHistoryEntry?.jobUrl,
      tailoredResumeId: resumeId,
      appwriteDoc: appwriteEntry as Record<string, unknown> | null,
    }),
    [appwriteEntry, effectiveState, resumeId, tailorHistoryEntry],
  );

  const navigateWithTemplate = (path: string, newTab = false) => {
    if (!resumeId) return;
    if (!newTab) {
      setCurrentResumeId(resumeId);
      if (resume) setCurrentResume(resume);
    }
    setSelectedTemplateStore(selectedTemplate);
    databases.updateDocument(DATABASE_ID, COLLECTIONS.resumes, resumeId, {
      template: selectedTemplate,
    }).catch(() => {});
    if (newTab) {
      window.open(path, '_blank', 'noopener,noreferrer');
    } else {
      navigate(path);
    }
  };

  const handleDesignedPDF = () => {
    if (!resumeId || !resume) return;
    setCurrentResumeId(resumeId);
    setCurrentResume(resume);
    setSelectedTemplateStore(selectedTemplate);
    setPdfExportOpen(true);
  };
  const handleAtsPDF = () => navigateWithTemplate(`/preview?id=${resumeId}&action=ats-pdf`, true);
  const handleDocx = () => navigateWithTemplate(`/preview?id=${resumeId}&action=docx`, true);

  const handleOpenEditor = () => {
    if (!resumeId) return;
    setCurrentResumeId(resumeId);
    if (resume) setCurrentResume(resume);
    navigate(`/editor?id=${resumeId}`);
  };

  const handleCoverLetter = () => {
    if (!resumeId) return;
    setCurrentResumeId(resumeId);
    if (resume) setCurrentResume(resume);
    saveTailorJobDescriptionForResume(resumeId, jobContext.jobDescription);
    saveCoverLetterPrefill({
      resumeId,
      jobTitle: jobContext.jobTitle,
      company: jobContext.company,
      jobDescription: jobContext.jobDescription,
      jobUrl: jobContext.jobUrl,
    });
    navigate(
      `/cover-letter/new?resumeId=${encodeURIComponent(resumeId)}&source=tailor-result`,
      {
        state: {
          resumeId,
          fromTailorResult: true,
          returnTo: `/tailoring-hub/result/${resumeId}`,
          jobTitle: jobContext.jobTitle,
          company: jobContext.company,
          jobDescription: jobContext.jobDescription,
        },
      },
    );
  };

  const scoreDelta = effectiveState.scoreBeforeAfter
    ? Math.max(0, effectiveState.scoreBeforeAfter.after - effectiveState.scoreBeforeAfter.before)
    : 0;

  const sourceResume = useMemo(() => {
    const parentId = dbResume?.parent_resume_id;
    if (!parentId || !allResumes) return null;
    const parent = allResumes.find((r: DatabaseResume) => r.$id === parentId);
    return parent ? dbToResumeData(parent) : null;
  }, [allResumes, dbResume?.parent_resume_id]);

  const tailorResult = tailorHistoryEntry?.tailorResult as SuperTailorResult | undefined;
  const canCompare = !!(resume && sourceResume);

  const appliedSections = useMemo((): TailorSectionId[] => {
    const fromState = effectiveState.appliedSections;
    if (fromState?.length) {
      return fromState as TailorSectionId[];
    }
    return ['summary', 'skills', 'experience', 'education', 'projects', 'certifications', 'awards'];
  }, [effectiveState.appliedSections]);

  const linkedCoverLetterIdFromNav = (location.state as ResultState | null)?.coverLetterId;
  const linkedCoverLetterId = useMemo(() => (
    linkedCoverLetterIdFromNav
    ?? (resumeId ? readLinkedCoverLetterForTailoredResume(resumeId) : null)
  ), [linkedCoverLetterIdFromNav, resumeId]);

  useEffect(() => {
    if (!resumeId || !linkedCoverLetterIdFromNav) return;
    saveLinkedCoverLetterForTailoredResume(resumeId, linkedCoverLetterIdFromNav);
  }, [linkedCoverLetterIdFromNav, resumeId]);

  const { data: linkedCoverLetterById } = useCoverLetter(linkedCoverLetterId);

  const { data: linkedCoverLetterByResume } = useQuery({
    queryKey: ['cover-letter-by-tailored-resume', resumeId],
    queryFn: async () => {
      if (!resumeId) return null;
      try {
        const res = await databases.listDocuments(DATABASE_ID, COLLECTIONS.cover_letters, [
          Query.equal('resume_id', [resumeId]),
          Query.orderDesc('$createdAt'),
          Query.limit(1),
        ]);
        const doc = res.documents[0];
        return doc ? parseCoverLetter(doc as Record<string, unknown>) : null;
      } catch {
        return null;
      }
    },
    enabled: !!resumeId && !linkedCoverLetterId,
    staleTime: 60 * 1000,
    retry: false,
  });

  const linkedCoverLetter = linkedCoverLetterById ?? linkedCoverLetterByResume ?? null;
  const hasApplicationBundle = !!linkedCoverLetter;

  const handleDownloadCoverLetterPdf = useCallback(async () => {
    if (!linkedCoverLetter || coverLetterDownloadBusy) return;
    setCoverLetterDownloadBusy(true);
    try {
      const { downloadCoverLetterPDF } = await import('@/lib/coverLetterPdfGenerator');
      await downloadCoverLetterPDF({
        job_title: linkedCoverLetter.job_title || jobContext.jobTitle || 'Cover Letter',
        company: linkedCoverLetter.company ?? jobContext.company ?? null,
        content: linkedCoverLetter.content,
        title: linkedCoverLetter.title,
        tone: linkedCoverLetter.tone ?? undefined,
        template_style: linkedCoverLetter.template_style ?? undefined,
      });
      toast.success('Cover letter PDF downloaded');
    } catch {
      toast.error('Failed to download cover letter PDF');
    } finally {
      setCoverLetterDownloadBusy(false);
    }
  }, [coverLetterDownloadBusy, jobContext.company, jobContext.jobTitle, linkedCoverLetter]);

  const handleDownloadBoth = useCallback(() => {
    if (linkedCoverLetter) {
      void handleDownloadCoverLetterPdf();
    }
    handleDesignedPDF();
    toast.message('Download your tailored CV, then grab the cover letter PDF from the bundle panel.');
  }, [handleDownloadCoverLetterPdf, linkedCoverLetter]);

  return (
    <div className="jmw-result-page jmw-result-page--compare">
      <header className="jmw-result-topbar">
        <button
          type="button"
          onClick={() => navigate('/tailoring-hub')}
          className="jmw-result-topbar__back"
          aria-label="Back to Tailoring Hub"
        >
          <ArrowLeft className="w-4 h-4" aria-hidden />
        </button>

        <div className="jmw-result-topbar__title-block min-w-0">
          <div className="flex items-center gap-1.5">
            <CheckCircle2 className="w-4 h-4 text-emerald-500 shrink-0" aria-hidden />
            <span className="jmw-result-topbar__eyebrow">Tailored CV ready</span>
          </div>
          <h1 className="jmw-result-topbar__title truncate">
            {isLoading ? 'Loading…' : dbResume?.title ?? 'Tailored CV'}
          </h1>
        </div>

        {(effectiveState.jobTitle || effectiveState.scoreBeforeAfter) && (
          <div className="jmw-result-topbar__meta hidden sm:flex">
            {effectiveState.jobTitle && (
              <span className="jmw-result-topbar__job truncate">
                <Briefcase className="w-3.5 h-3.5 shrink-0" aria-hidden />
                {effectiveState.jobTitle}
                {effectiveState.company ? ` · ${effectiveState.company}` : ''}
              </span>
            )}
            {effectiveState.scoreBeforeAfter && (
              <span className="jmw-result-topbar__score">
                <span className="text-muted-foreground">{effectiveState.scoreBeforeAfter.before}</span>
                <TrendingUp className="w-3.5 h-3.5 text-emerald-500" aria-hidden />
                <span className={cn(
                  'font-bold',
                  effectiveState.scoreBeforeAfter.after >= 70 ? 'text-emerald-500' : 'text-foreground',
                )}>
                  {effectiveState.scoreBeforeAfter.after}
                </span>
                {scoreDelta > 0 && (
                  <span className="jmw-score-delta jmw-score-delta--compact">+{scoreDelta}</span>
                )}
              </span>
            )}
            {effectiveState.jobUrl && (
              <a
                href={effectiveState.jobUrl}
                target="_blank"
                rel="noopener noreferrer"
                className="jmw-result-topbar__job-link"
                aria-label="Open job posting"
              >
                <ExternalLink className="w-3.5 h-3.5" aria-hidden />
              </a>
            )}
          </div>
        )}
      </header>

      <div className="jmw-result-body jmw-result-body--compare">
        {isLoading ? (
          <div className="flex flex-col items-center justify-center gap-3 py-20">
            <Loader2 className="w-8 h-8 animate-spin text-primary" aria-hidden />
            <p className="text-sm text-muted-foreground">Loading your tailored CV…</p>
          </div>
        ) : !resume ? (
          <div className="flex flex-col items-center justify-center gap-4 py-20 text-center">
            <p className="text-sm text-muted-foreground">Resume not found.</p>
            <Button variant="outline" onClick={() => navigate('/tailoring-hub')}>
              Back to Tailoring Hub
            </Button>
          </div>
        ) : (
          <div className={cn(
            'jmw-result-compare-layout',
            hasApplicationBundle && 'jmw-result-compare-layout--bundle',
          )}>
            <main className={cn(
              'jmw-result-compare-main',
              hasApplicationBundle && 'jmw-result-bundle-main',
            )}>
              {hasApplicationBundle ? (
                <div className="jmw-result-bundle-grid">
                  <div className="jmw-result-bundle-cv">
                    <p className="jmw-result-bundle-label">Tailored CV</p>
                    <ScaledResumePage resume={resume} templateId={selectedTemplate} />
                  </div>
                  <TailorResultCoverLetterPanel
                    coverLetter={linkedCoverLetter}
                    onEdit={() => navigate(`/cover-letter/edit/${linkedCoverLetter.id}`)}
                  />
                </div>
              ) : canCompare ? (
                <TailorResumeCompare
                  beforeResume={sourceResume!}
                  afterResume={resume}
                  templateId={selectedTemplate}
                  appliedSections={appliedSections}
                  tailorResult={tailorResult}
                />
              ) : (
                <div className="jmw-compare jmw-compare--single">
                  <ScaledResumePage resume={resume} templateId={selectedTemplate} />
                </div>
              )}
            </main>

            <TailorResultExportPanel
              selectedTemplate={selectedTemplate}
              onTemplateChange={handlePickTemplate}
              onDesignedPdf={handleDesignedPDF}
              onAtsPdf={handleAtsPDF}
              onDocx={handleDocx}
              onPreview={() => navigateWithTemplate(`/preview?id=${resumeId}`)}
              onEditor={handleOpenEditor}
              onCoverLetter={handleCoverLetter}
              resumeTitle={dbResume?.title}
              hasCoverLetter={hasApplicationBundle}
              onDownloadCoverLetter={handleDownloadCoverLetterPdf}
              onDownloadBoth={handleDownloadBoth}
              coverLetterBusy={coverLetterDownloadBusy}
            />

            <TailorQuickPdfExportDialog
              open={pdfExportOpen}
              onOpenChange={setPdfExportOpen}
              resume={resume}
              templateId={selectedTemplate}
              resumeDocId={resumeId}
              jobTitle={jobContext.jobTitle}
              company={jobContext.company}
            />
          </div>
        )}
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Info, Sparkles, User, FlaskConical } from 'lucide-react';
import { BackButton } from '@/components/ui/BackButton';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Sheet, SheetContent, SheetHeader, SheetTitle } from '@/components/ui/sheet';
import { Tooltip, TooltipContent, TooltipProvider, TooltipTrigger } from '@/components/ui/tooltip';
import { TemplateThumbnail } from '@/components/editor/TemplateThumbnail';
import { ErrorBoundary } from '@/components/ErrorBoundary';
import { templates, sampleResumeData, atsScoreColors, atsScoreDescriptions, atsScoreLabels } from '@/lib/templateData';
import { TemplateId, TemplateInfo, TemplateCustomization } from '@/types/resume';
import { useResumeStore } from '@/store/resumeStore';
import { useResumes, dbToResumeData } from '@/hooks/useResumes';
import { motion } from 'framer-motion';
import { TemplateAdvisorSheet } from '@/components/editor/TemplateAdvisorSheet';

type FilterCategory = 'all' | 'professional' | 'creative' | 'tech' | 'minimalist';

const FILTER_CHIPS: { value: FilterCategory; label: string }[] = [
  { value: 'all', label: 'All' },
  { value: 'professional', label: 'Professional' },
  { value: 'creative', label: 'Creative' },
  { value: 'tech', label: 'Tech' },
  { value: 'minimalist', label: 'Minimalist' },
];

export default function TemplatesPage() {
  const navigate = useNavigate();
  const [filter, setFilter] = useState<FilterCategory>('all');
  const [previewTemplate, setPreviewTemplate] = useState<TemplateInfo | null>(null);
  const [showAdvisor, setShowAdvisor] = useState(false);
  const [previewWithMyData, setPreviewWithMyData] = useState(false);
  const { setSelectedTemplate, updateResume } = useResumeStore();
  const { data: resumes = [] } = useResumes();
  const myResumeData = resumes.length > 0 ? dbToResumeData(resumes[0]) : null;

  const filtered = filter === 'all' ? templates : templates.filter(t => t.category === filter);

  const handleUseTemplate = (id: TemplateId) => {
    const { currentResumeId } = useResumeStore.getState();
    setSelectedTemplate(id);
    if (currentResumeId) {
      updateResume({ templateId: id });
      navigate('/editor');
    } else {
      navigate('/dashboard?action=create');
      toast.info('Create a resume first, then apply this template from the editor.');
    }
  };

  const handleAdvisorApply = (templateId: TemplateId, customization: Partial<TemplateCustomization>) => {
    const { currentResumeId } = useResumeStore.getState();
    setSelectedTemplate(templateId);
    if (currentResumeId) {
      updateResume({ templateId, customization: customization as any });
      navigate('/editor');
    } else {
      navigate('/dashboard?action=create');
      toast.info('Create a resume first, then apply this template from the editor.');
    }
  };

  return (
    <div className="flex-1 flex flex-col min-h-0 overflow-hidden">
      {/* Header */}
      <div className="shrink-0 flex items-center gap-3 px-4 h-12 border-b border-border bg-background/95 backdrop-blur-sm">
        <BackButton />
        <h1 className="text-lg font-bold text-foreground">Templates</h1>
      </div>

      {/* Filter Chips */}
      <div className="shrink-0 flex gap-2 px-4 py-3 overflow-x-auto">
        {FILTER_CHIPS.map(chip => (
          <button
            key={chip.value}
            onClick={() => setFilter(chip.value)}
            className={`px-4 py-2.5 min-h-[44px] rounded-full text-sm font-medium whitespace-nowrap transition-all touch-manipulation active:scale-95 ${
              filter === chip.value
                ? 'bg-primary text-primary-foreground'
                : 'bg-card border border-border text-muted-foreground hover:text-foreground'
            }`}
            aria-label={`Filter by ${chip.label}`}
          >
            {chip.label}
          </button>
        ))}
        <button
          onClick={() => setShowAdvisor(true)}
          className="flex items-center gap-1.5 px-4 py-2.5 min-h-[44px] rounded-full text-sm font-medium whitespace-nowrap transition-all touch-manipulation active:scale-95 bg-primary/10 text-primary border border-primary/30 hover:bg-primary/20"
          aria-label="AI Template Advisor"
        >
          <Sparkles className="w-4 h-4" />
          AI Suggest
        </button>
      </div>

      {/* Grid */}
      <div className="flex-1 overflow-y-auto px-4 pb-6">
        <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
          {filtered.map((tmpl, i) => (
            <motion.button
              key={tmpl.id}
              initial={{ opacity: 0, y: 16 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: Math.min(i * 0.03, 0.15) }}
              onClick={() => setPreviewTemplate(tmpl)}
              className="relative p-2.5 rounded-2xl border-2 border-border hover:border-primary/50 hover:scale-[1.02] hover:shadow-xl transition-all text-left touch-manipulation active:scale-[0.98]"
              aria-label={`Preview ${tmpl.name} template`}
            >
              <TemplateThumbnail templateId={tmpl.id} resume={sampleResumeData as any} />
              <div className="mt-2">
                <p className="font-semibold text-sm text-foreground">{tmpl.name}</p>
                <p className="text-xs text-muted-foreground line-clamp-1">{tmpl.description}</p>
              </div>
              <TooltipProvider>
                <Tooltip>
                  <TooltipTrigger asChild>
                    <Badge
                      variant="outline"
                      className={`absolute top-1.5 left-1.5 text-[8px] px-1.5 py-0.5 cursor-help ${atsScoreColors[tmpl.atsScore]}`}
                    >
                      {atsScoreLabels[tmpl.atsScore]}
                      <Info className="w-2 h-2 ml-0.5 opacity-60" />
                    </Badge>
                  </TooltipTrigger>
                  <TooltipContent side="bottom" className="max-w-[200px] text-center">
                    <p className="text-xs">{atsScoreDescriptions[tmpl.atsScore]}</p>
                  </TooltipContent>
                </Tooltip>
              </TooltipProvider>
            </motion.button>
          ))}
        </div>
      </div>

      {/* Preview Sheet */}
      <Sheet open={!!previewTemplate} onOpenChange={(open) => { setPreviewTemplate(open ? previewTemplate : null); setPreviewWithMyData(false); }}>
        <SheetContent side="bottom" className="h-[80vh]">
          {previewTemplate && (
            <>
              <SheetHeader className="pb-2">
                <SheetTitle>{previewTemplate.name} Template</SheetTitle>
              </SheetHeader>
              {myResumeData && (
                <div className="flex gap-2 pb-3">
                  <button
                    onClick={() => setPreviewWithMyData(false)}
                    className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium border transition-colors ${!previewWithMyData ? 'bg-primary text-primary-foreground border-primary' : 'border-border text-muted-foreground hover:text-foreground'}`}
                  >
                    <FlaskConical className="w-3 h-3" />
                    Sample data
                  </button>
                  <button
                    onClick={() => setPreviewWithMyData(true)}
                    className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium border transition-colors ${previewWithMyData ? 'bg-primary text-primary-foreground border-primary' : 'border-border text-muted-foreground hover:text-foreground'}`}
                  >
                    <User className="w-3 h-3" />
                    My resume
                  </button>
                </div>
              )}
              <div className="flex-1 overflow-y-auto space-y-4 pb-4">
                <div className="max-w-sm mx-auto">
                  <ErrorBoundary fallback={
                    <div className="flex flex-col items-center justify-center h-48 text-muted-foreground gap-2">
                      <p className="text-sm">Preview unavailable for this resume.</p>
                    </div>
                  }>
                    <TemplateThumbnail templateId={previewTemplate.id} resume={(previewWithMyData && myResumeData ? myResumeData : sampleResumeData) as any} />
                  </ErrorBoundary>
                </div>
                <p className="text-muted-foreground text-sm">{previewTemplate.description}</p>
                <div className="flex items-center gap-2">
                  <TooltipProvider>
                    <Tooltip>
                      <TooltipTrigger asChild>
                        <Badge variant="outline" className={`cursor-help ${atsScoreColors[previewTemplate.atsScore]}`}>
                          {atsScoreLabels[previewTemplate.atsScore]}
                          <Info className="w-3 h-3 ml-1 opacity-60" />
                        </Badge>
                      </TooltipTrigger>
                      <TooltipContent side="top" className="max-w-[220px] text-center">
                        <p className="text-xs">{atsScoreDescriptions[previewTemplate.atsScore]}</p>
                      </TooltipContent>
                    </Tooltip>
                  </TooltipProvider>
                  <Badge variant="secondary" className="text-xs capitalize">{previewTemplate.category}</Badge>
                </div>
                <Button
                  onClick={() => {
                    handleUseTemplate(previewTemplate.id);
                    setPreviewTemplate(null);
                  }}
                  className="w-full h-12 rounded-xl"
                  size="lg"
                >
                  Use This Template
                </Button>
              </div>
            </>
          )}
        </SheetContent>
      </Sheet>

      {/* AI Advisor Sheet */}
      <TemplateAdvisorSheet
        open={showAdvisor}
        onOpenChange={setShowAdvisor}
        onApply={handleAdvisorApply}
      />
    </div>
  );
}

